    /// Apply GLA Rebel residual fire: intended-only gun damage residual.
    /// Apply USA Ranger residual fire: rifle intended-only or FlashBang dual-radius splash.
    fn apply_ranger_residual_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
        flashbang_slot: bool,
    ) -> (u32, bool) {
        use crate::game_logic::host_ranger::{
            flashbang_damage_at, is_legal_ranger_target, FLASHBANG_SECONDARY_RADIUS,
            RANGER_FLASHBANG_FIRE_AUDIO, RANGER_RIFLE_DAMAGE, RANGER_RIFLE_FIRE_AUDIO,
        };

        let source_team = source
            .and_then(|sid| self.objects.get(&sid).map(|o| o.team))
            .unwrap_or(Team::Neutral);

        let mut hits = 0u32;
        let mut any_destroyed = false;

        if flashbang_slot {
            // Dual-radius flashbang residual (Primary 35/10 + Secondary 10/40).
            let victims: Vec<(ObjectId, f32, bool)> = self
                .objects
                .iter()
                .filter_map(|(id, obj)| {
                    if obj.team == source_team {
                        return None;
                    }
                    let combat_kind = obj.is_kind_of(KindOf::Attackable)
                        || obj.is_kind_of(KindOf::Structure)
                        || obj.is_kind_of(KindOf::Infantry)
                        || obj.is_kind_of(KindOf::Vehicle)
                        || obj.is_kind_of(KindOf::Aircraft);
                    if !is_legal_ranger_target(
                        obj.is_alive(),
                        source == Some(*id),
                        obj.status.under_construction,
                        combat_kind,
                    ) {
                        return None;
                    }
                    let pos = obj.get_position();
                    let dx = pos.x - impact.x;
                    let dz = pos.z - impact.z;
                    let dist = (dx * dx + dz * dz).sqrt();
                    let is_intended = intended_target == Some(*id);
                    // Scan only intended + secondary ring (primary is subset).
                    if !is_intended && dist > FLASHBANG_SECONDARY_RADIUS {
                        return None;
                    }
                    let dmg = flashbang_damage_at(is_intended, dist);
                    if dmg <= 0.0 {
                        return None;
                    }
                    Some((*id, dmg, is_intended))
                })
                .collect();

            for (vid, dmg, _intended) in victims {
                if let Some(obj) = self.objects.get_mut(&vid) {
                    let destroyed = obj.take_damage_from(dmg, source);
                    hits = hits.saturating_add(1);
                    if destroyed {
                        any_destroyed = true;
                        self.mark_object_for_destruction(vid, Some(source_team));
                    }
                }
            }

            self.ranger_residual_flashbang_fires =
                self.ranger_residual_flashbang_fires.saturating_add(1);
            self.ranger_residual_units_hit = self.ranger_residual_units_hit.saturating_add(hits);

            self.queue_audio_event(
                AudioEventRequest::new(RANGER_FLASHBANG_FIRE_AUDIO)
                    .with_position(impact)
                    .with_priority(155),
            );
        } else {
            // Rifle residual: intended-only PrimaryDamage 5.
            let damage = source
                .and_then(|sid| self.objects.get(&sid))
                .and_then(|o| o.weapon.as_ref().map(|w| w.damage))
                .unwrap_or(RANGER_RIFLE_DAMAGE);

            let Some(target_id) = intended_target else {
                return (0, false);
            };
            let Some(target) = self.objects.get(&target_id) else {
                return (0, false);
            };
            let combat_kind = target.is_kind_of(KindOf::Attackable)
                || target.is_kind_of(KindOf::Structure)
                || target.is_kind_of(KindOf::Infantry)
                || target.is_kind_of(KindOf::Vehicle)
                || target.is_kind_of(KindOf::Aircraft);
            if !is_legal_ranger_target(
                target.is_alive(),
                source == Some(target_id),
                target.status.under_construction,
                combat_kind,
            ) {
                return (0, false);
            }
            let target_pos = target.get_position();

            if let Some(obj) = self.objects.get_mut(&target_id) {
                let destroyed = obj.take_damage_from(damage, source);
                hits = 1;
                if destroyed {
                    any_destroyed = true;
                    self.mark_object_for_destruction(target_id, Some(source_team));
                }
            }

            self.ranger_residual_rifle_fires = self.ranger_residual_rifle_fires.saturating_add(1);
            self.ranger_residual_units_hit = self.ranger_residual_units_hit.saturating_add(hits);

            self.queue_audio_event(
                AudioEventRequest::new(RANGER_RIFLE_FIRE_AUDIO)
                    .with_position(target_pos)
                    .with_priority(150),
            );
        }

        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(impact),
                self.frame,
                sid,
                intended_target,
            );
        }

        (hits, any_destroyed)
    }

    fn apply_rebel_residual_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
    ) -> (u32, bool) {
        use crate::game_logic::host_gla_rebel::{
            is_legal_rebel_target, REBEL_DAMAGE, REBEL_FIRE_AUDIO,
        };

        let damage = source
            .and_then(|sid| self.objects.get(&sid))
            .and_then(|o| o.weapon.as_ref().map(|w| w.damage))
            .unwrap_or(REBEL_DAMAGE);
        let source_team = source
            .and_then(|sid| self.objects.get(&sid).map(|o| o.team))
            .unwrap_or(Team::Neutral);

        let Some(target_id) = intended_target else {
            return (0, false);
        };
        let Some(target) = self.objects.get(&target_id) else {
            return (0, false);
        };
        let combat_kind = target.is_kind_of(KindOf::Attackable)
            || target.is_kind_of(KindOf::Structure)
            || target.is_kind_of(KindOf::Infantry)
            || target.is_kind_of(KindOf::Vehicle)
            || target.is_kind_of(KindOf::Aircraft);
        if !is_legal_rebel_target(
            target.is_alive(),
            source == Some(target_id),
            target.status.under_construction,
            combat_kind,
        ) {
            return (0, false);
        }
        let target_pos = target.get_position();

        let mut hits = 0u32;
        let mut any_destroyed = false;
        if let Some(obj) = self.objects.get_mut(&target_id) {
            let destroyed = obj.take_damage_from(damage, source);
            hits = 1;
            if destroyed {
                any_destroyed = true;
                self.mark_object_for_destruction(target_id, Some(source_team));
            }
        }

        self.rebel_residual_fires = self.rebel_residual_fires.saturating_add(1);

        self.queue_audio_event(
            AudioEventRequest::new(REBEL_FIRE_AUDIO)
                .with_position(target_pos)
                .with_priority(150),
        );
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(target_pos),
                self.frame,
                sid,
                intended_target,
            );
        }

        (hits, any_destroyed)
    }

    /// Apply China MiniGunner residual fire: intended-only ground/AA residual.
    fn apply_minigunner_residual_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
        slot: u8,
    ) -> (u32, bool) {
        use crate::game_logic::host_minigunner::{
            has_chain_guns_upgrade, is_legal_minigunner_target, minigunner_damage_with_chain_guns,
            MINIGUNNER_AA_FIRE_AUDIO, MINIGUNNER_AIR_DAMAGE, MINIGUNNER_FIRE_AUDIO,
            MINIGUNNER_GROUND_DAMAGE,
        };

        let dmg = source
            .and_then(|id| self.objects.get(&id))
            .map(|o| {
                let chain = has_chain_guns_upgrade(&o.applied_upgrades);
                // Prefer live weapon damage (already chain/horde-refreshed).
                if slot == 1 {
                    o.secondary_weapon
                        .as_ref()
                        .map(|w| w.damage)
                        .unwrap_or_else(|| {
                            minigunner_damage_with_chain_guns(MINIGUNNER_AIR_DAMAGE, chain)
                        })
                } else {
                    o.weapon.as_ref().map(|w| w.damage).unwrap_or_else(|| {
                        minigunner_damage_with_chain_guns(MINIGUNNER_GROUND_DAMAGE, chain)
                    })
                }
            })
            .unwrap_or(MINIGUNNER_GROUND_DAMAGE);

        let mut hits = 0u32;
        let mut any_destroyed = false;
        let source_team = source.and_then(|id| self.objects.get(&id).map(|o| o.team));

        let Some(tid) = intended_target else {
            return (0, false);
        };
        if let Some(obj) = self.objects.get_mut(&tid) {
            let combat_kind = obj.is_kind_of(KindOf::Attackable)
                || obj.is_kind_of(KindOf::Structure)
                || obj.is_kind_of(KindOf::Infantry)
                || obj.is_kind_of(KindOf::Vehicle)
                || obj.is_kind_of(KindOf::Aircraft);
            if is_legal_minigunner_target(
                obj.is_alive(),
                source == Some(tid),
                obj.status.under_construction,
                combat_kind,
            ) {
                let destroyed = obj.take_damage_from(dmg, source);
                hits = 1;
                if destroyed {
                    any_destroyed = true;
                    self.mark_object_for_destruction(tid, source_team);
                }
            }
        }

        if slot == 1 {
            self.minigunner_residual_aa_fires = self.minigunner_residual_aa_fires.saturating_add(1);
        } else {
            self.minigunner_residual_ground_fires =
                self.minigunner_residual_ground_fires.saturating_add(1);
        }

        let audio = if slot == 1 {
            MINIGUNNER_AA_FIRE_AUDIO
        } else {
            MINIGUNNER_FIRE_AUDIO
        };
        self.queue_audio_event(
            AudioEventRequest::new(audio)
                .with_position(impact)
                .with_priority(150),
        );
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(impact),
                self.frame,
                sid,
                intended_target,
            );
        }

        (hits, any_destroyed)
    }

    /// Advance MiniGunner continuous-fire ramp residual after a successful shot.
    fn advance_minigunner_continuous_fire(
        &mut self,
        attacker_id: ObjectId,
        target_id: Option<ObjectId>,
        slot: u8,
    ) {
        use crate::game_logic::host_battlemaster::has_nationalism_upgrade;
        use crate::game_logic::host_gattling_tank::GattlingFireLevel;
        use crate::game_logic::host_minigunner::{
            has_chain_guns_upgrade, minigunner_air_weapon, minigunner_coast_until_after_shot,
            minigunner_ground_weapon, minigunner_on_shot_fired, MINIGUNNER_RAPID_FIRE_AUDIO,
        };

        let frame = self.frame;
        let Some(obj) = self.objects.get_mut(&attacker_id) else {
            return;
        };
        let prev_level = GattlingFireLevel::from_u8(obj.continuous_fire_level);
        let prev_consec = obj.continuous_fire_consecutive;
        let prev_victim = if obj.continuous_fire_victim == 0 {
            None
        } else {
            Some(obj.continuous_fire_victim)
        };
        let new_victim = target_id.map(|id| id.0);
        let coast_until = obj.continuous_fire_coast_until_frame;
        let in_horde = obj.weapon_bonus_horde;
        let nationalism = has_nationalism_upgrade(&obj.applied_upgrades) && in_horde;
        let chain = has_chain_guns_upgrade(&obj.applied_upgrades);

        let (new_level, consecutive, entered_fast) = minigunner_on_shot_fired(
            prev_level,
            prev_consec,
            prev_victim,
            new_victim,
            frame,
            coast_until,
        );

        obj.continuous_fire_level = new_level.as_u8();
        obj.continuous_fire_consecutive = consecutive;
        obj.continuous_fire_victim = new_victim.unwrap_or(0);
        obj.continuous_fire_coast_until_frame =
            minigunner_coast_until_after_shot(frame, new_level, in_horde, nationalism);

        // Rebind weapons with ramped + horde reload residual.
        if let Some(w) = obj.weapon.as_mut() {
            let refreshed = minigunner_ground_weapon(new_level, chain, in_horde, nationalism);
            w.damage = refreshed.damage;
            w.range = refreshed.range;
            w.reload_time = refreshed.reload_time;
            w.can_target_air = false;
            w.can_target_ground = true;
        }
        if let Some(w) = obj.secondary_weapon.as_mut() {
            let refreshed = minigunner_air_weapon(new_level, chain, in_horde, nationalism);
            w.damage = refreshed.damage;
            w.range = refreshed.range;
            w.reload_time = refreshed.reload_time;
            w.can_target_air = true;
            w.can_target_ground = false;
        }

        let pos = obj.get_position();

        if new_level == GattlingFireLevel::Mean && prev_level != GattlingFireLevel::Mean {
            self.minigunner_residual_ramp_mean =
                self.minigunner_residual_ramp_mean.saturating_add(1);
        }
        let became_fast = entered_fast
            || (new_level == GattlingFireLevel::Fast && prev_level != GattlingFireLevel::Fast);
        if became_fast {
            self.minigunner_residual_ramp_fast =
                self.minigunner_residual_ramp_fast.saturating_add(1);
            self.queue_audio_event(
                AudioEventRequest::new(MINIGUNNER_RAPID_FIRE_AUDIO)
                    .with_object(attacker_id)
                    .with_position(pos)
                    .with_priority(140),
            );
        }
        let _ = slot; // slot honesty counted in apply_minigunner_residual_at
    }

    /// Apply Colonel Burton residual fire: knife one-shot vs close infantry, else sniper.
    fn apply_burton_residual_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
    ) -> (u32, bool) {
        use crate::game_logic::host_colonel_burton::{
            distance_2d, is_legal_burton_target, should_apply_burton_knife_residual,
            BURTON_KNIFE_DAMAGE, BURTON_KNIFE_FIRE_AUDIO, BURTON_SNIPER_DAMAGE,
            BURTON_SNIPER_FIRE_AUDIO,
        };

        let source_team = source
            .and_then(|sid| self.objects.get(&sid).map(|o| o.team))
            .unwrap_or(Team::Neutral);
        let source_pos = source
            .and_then(|sid| self.objects.get(&sid).map(|o| o.get_position()))
            .unwrap_or(impact);

        let Some(target_id) = intended_target else {
            return (0, false);
        };
        let Some(target) = self.objects.get(&target_id) else {
            return (0, false);
        };
        let combat_kind = target.is_kind_of(KindOf::Attackable)
            || target.is_kind_of(KindOf::Structure)
            || target.is_kind_of(KindOf::Infantry)
            || target.is_kind_of(KindOf::Vehicle)
            || target.is_kind_of(KindOf::Aircraft);
        if !is_legal_burton_target(
            target.is_alive(),
            source == Some(target_id),
            target.status.under_construction,
            combat_kind,
        ) {
            return (0, false);
        }
        let target_pos = target.get_position();
        let dist = distance_2d(source_pos.x, source_pos.z, target_pos.x, target_pos.z);
        let target_is_infantry = target.is_kind_of(KindOf::Infantry);
        let knife = should_apply_burton_knife_residual(true, target_is_infantry, true, dist);
        let damage = if knife {
            BURTON_KNIFE_DAMAGE
        } else {
            source
                .and_then(|sid| self.objects.get(&sid))
                .and_then(|o| o.weapon.as_ref().map(|w| w.damage))
                .unwrap_or(BURTON_SNIPER_DAMAGE)
        };

        let mut hits = 0u32;
        let mut any_destroyed = false;
        if let Some(obj) = self.objects.get_mut(&target_id) {
            let destroyed = obj.take_damage_from(damage, source);
            hits = 1;
            if destroyed {
                any_destroyed = true;
                self.mark_object_for_destruction(target_id, Some(source_team));
            }
        }

        if knife {
            self.burton_residual_knife_kills = self.burton_residual_knife_kills.saturating_add(1);
        } else {
            self.burton_residual_sniper_fires = self.burton_residual_sniper_fires.saturating_add(1);
        }

        let audio = if knife {
            BURTON_KNIFE_FIRE_AUDIO
        } else {
            BURTON_SNIPER_FIRE_AUDIO
        };
        self.queue_audio_event(
            AudioEventRequest::new(audio)
                .with_position(target_pos)
                .with_priority(160),
        );
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(target_pos),
                self.frame,
                sid,
                intended_target,
            );
        }

        (hits, any_destroyed)
    }

    /// Refresh RPG Trooper residual from current AP Rockets upgrade tag.
    fn refresh_rpg_trooper_weapon(&mut self, object_id: ObjectId) {
        use crate::game_logic::host_rpg_trooper::{
            has_ap_rockets_upgrade, is_rpg_trooper_template, rpg_trooper_weapon,
        };
        let Some(obj) = self.objects.get_mut(&object_id) else {
            return;
        };
        if !is_rpg_trooper_template(&obj.template_name) {
            return;
        }
        let ap = has_ap_rockets_upgrade(&obj.applied_upgrades);
        let last_fire = obj.weapon.as_ref().map(|w| w.last_fire_time).unwrap_or(0.0);
        let mut w = rpg_trooper_weapon(ap);
        w.last_fire_time = last_fire;
        obj.weapon = Some(w);
    }

    /// Apply AP Rockets residual tag to an RPG Trooper (damage × 1.25).
    pub fn apply_rpg_trooper_ap_rockets_upgrade(&mut self, object_id: ObjectId) -> bool {
        use crate::game_logic::host_rpg_trooper::{
            is_rpg_trooper_template, UPGRADE_GLA_AP_ROCKETS,
        };
        let Some(obj) = self.objects.get_mut(&object_id) else {
            return false;
        };
        if !is_rpg_trooper_template(&obj.template_name) {
            return false;
        }
        obj.applied_upgrades
            .insert(UPGRADE_GLA_AP_ROCKETS.to_string());
        self.rpg_trooper_residual_ap_upgrades =
            self.rpg_trooper_residual_ap_upgrades.saturating_add(1);
        self.refresh_rpg_trooper_weapon(object_id);
        true
    }

    /// Apply RPG Trooper residual rocket fire (primary on intended + small splash radius).
    fn apply_rpg_trooper_residual_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
    ) -> (u32, bool) {
        use crate::game_logic::host_rpg_trooper::{
            is_legal_rpg_trooper_splash_target, rpg_trooper_splash_damage_at, RPG_TROOPER_DAMAGE,
            RPG_TROOPER_FIRE_AUDIO, RPG_TROOPER_SPLASH_RADIUS,
        };

        let damage = source
            .and_then(|sid| self.objects.get(&sid))
            .and_then(|o| o.weapon.as_ref().map(|w| w.damage))
            .unwrap_or(RPG_TROOPER_DAMAGE);
        let source_team = source
            .and_then(|sid| self.objects.get(&sid).map(|o| o.team))
            .unwrap_or(Team::Neutral);

        let impact_xz = (impact.x, impact.z);
        let mut hits = 0u32;
        let mut any_destroyed = false;
        let mut destroy_ids: Vec<(ObjectId, Option<Team>)> = Vec::new();

        let candidates: Vec<(ObjectId, f32, bool)> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                if source == Some(*id) {
                    return None;
                }
                let combat_kind = obj.is_kind_of(KindOf::Attackable)
                    || obj.is_kind_of(KindOf::Structure)
                    || obj.is_kind_of(KindOf::Infantry)
                    || obj.is_kind_of(KindOf::Vehicle)
                    || obj.is_kind_of(KindOf::Aircraft);
                if !is_legal_rpg_trooper_splash_target(
                    obj.is_alive(),
                    false,
                    obj.status.under_construction,
                    combat_kind,
                ) {
                    return None;
                }
                let pos = obj.get_position();
                let dist = {
                    let dx = impact_xz.0 - pos.x;
                    let dz = impact_xz.1 - pos.z;
                    (dx * dx + dz * dz).sqrt()
                };
                let is_intended = intended_target == Some(*id);
                if is_intended || dist <= RPG_TROOPER_SPLASH_RADIUS {
                    Some((*id, dist, is_intended))
                } else {
                    None
                }
            })
            .collect();

        for (id, dist, is_intended) in candidates {
            let dmg = rpg_trooper_splash_damage_at(is_intended, dist, damage);
            if dmg <= 0.0 {
                continue;
            }
            if let Some(obj) = self.objects.get_mut(&id) {
                let destroyed = obj.take_damage_from(dmg, source);
                hits = hits.saturating_add(1);
                if destroyed {
                    any_destroyed = true;
                    destroy_ids.push((id, Some(source_team)));
                }
            }
        }

        for (id, killer) in destroy_ids {
            self.mark_object_for_destruction(id, killer);
        }

        self.rpg_trooper_residual_fires = self.rpg_trooper_residual_fires.saturating_add(1);
        self.rpg_trooper_residual_units_hit =
            self.rpg_trooper_residual_units_hit.saturating_add(hits);

        self.queue_audio_event(
            AudioEventRequest::new(RPG_TROOPER_FIRE_AUDIO)
                .with_position(impact)
                .with_priority(150),
        );
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(impact),
                self.frame,
                sid,
                intended_target,
            );
        }

        (hits, any_destroyed)
    }

    /// Apply GLA Terrorist residual: SuicideDynamitePack AOE at self + destroy self.
    ///
    /// Chem Beta/Gamma + Demo death-weapon residual profiles applied.
    /// Fail-closed: not ConvertToCarBomb matrix / SlowDeath fling / OCL particle bones.
    fn apply_terrorist_residual_at(
        &mut self,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
    ) -> (u32, bool) {
        use crate::game_logic::host_terrorist::{
            is_legal_terrorist_aoe_target, suicide_dynamite_damage_at_profile,
            terrorist_death_profile, TERRORIST_DETONATE_AUDIO,
        };

        let Some(source_id) = source else {
            return (0, false);
        };
        let Some(source_obj) = self.objects.get(&source_id) else {
            return (0, false);
        };
        if !source_obj.is_alive() {
            return (0, false);
        }
        let source_team = source_obj.team;
        let center = source_obj.get_position();
        let template_name = source_obj.template_name.clone();
        let has_gamma = source_obj.has_upgrade_tag("Chem_Upgrade_GLAAnthraxGamma")
            || source_obj.has_upgrade_tag("Upgrade_GLAAnthraxGamma")
            || source_obj.has_upgrade_tag("Chem_Upgrade_GLAAnthraxGamma");
        let has_beta = source_obj.has_upgrade_tag("Upgrade_GLAAnthraxBeta")
            || source_obj.has_upgrade_tag("Chem_Upgrade_GLAAnthraxBeta");
        let profile = terrorist_death_profile(&template_name, has_gamma, has_beta);
        let secondary_radius = profile.secondary_radius();

        let mut hits = 0u32;
        let mut any_destroyed = false;
        let mut damage_dealt = 0.0f32;
        let mut destroy_ids: Vec<(ObjectId, Option<Team>)> = Vec::new();

        let candidates: Vec<(ObjectId, f32)> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                if *id == source_id {
                    return None;
                }
                let combat_kind = obj.is_kind_of(KindOf::Attackable)
                    || obj.is_kind_of(KindOf::Structure)
                    || obj.is_kind_of(KindOf::Infantry)
                    || obj.is_kind_of(KindOf::Vehicle)
                    || obj.is_kind_of(KindOf::Aircraft);
                if !is_legal_terrorist_aoe_target(
                    obj.is_alive(),
                    false,
                    obj.status.under_construction,
                    combat_kind,
                ) {
                    return None;
                }
                let pos = obj.get_position();
                let dist = {
                    let dx = center.x - pos.x;
                    let dz = center.z - pos.z;
                    (dx * dx + dz * dz).sqrt()
                };
                if dist <= secondary_radius {
                    Some((*id, dist))
                } else {
                    None
                }
            })
            .collect();

        for (id, dist) in candidates {
            let dmg = suicide_dynamite_damage_at_profile(profile, dist);
            if dmg <= 0.0 {
                continue;
            }
            if let Some(obj) = self.objects.get_mut(&id) {
                let applied = dmg.min(obj.health.current.max(0.0));
                let destroyed = obj.take_damage_from(dmg, source);
                hits = hits.saturating_add(1);
                damage_dealt += applied;
                if destroyed {
                    any_destroyed = true;
                    destroy_ids.push((id, Some(source_team)));
                }
            }
        }

        // Intended-target residual honesty: ensure we counted the attack target
        // even if already dead/out of range residual (fail-closed soft).
        let _ = intended_target;

        for (id, killer) in destroy_ids {
            self.mark_object_for_destruction(id, killer);
        }

        // Chem Beta/Gamma residual: spawn MediumPoisonField at suicide epicenter.
        if profile.spawns_poison() {
            let _ = self.toxin_tractor.spawn_medium_field(
                source_id,
                source_team,
                center,
                self.frame,
                profile.poison_anthrax_tier(),
            );
        }

        // Self-kill residual (TerroristSuicideWeapon SUICIDED + FireWeaponWhenDead).
        if let Some(src) = self.objects.get_mut(&source_id) {
            src.status.destroyed = true;
        }
        self.mark_object_for_destruction(source_id, Some(source_team));

        self.terrorist_residual_detonations = self.terrorist_residual_detonations.saturating_add(1);
        self.terrorist_residual_units_hit = self.terrorist_residual_units_hit.saturating_add(hits);
        self.terrorist_residual_damage_dealt += damage_dealt;

        self.queue_audio_event(
            AudioEventRequest::new(TERRORIST_DETONATE_AUDIO)
                .with_object(source_id)
                .with_position(center)
                .with_priority(190),
        );
        let _ = self.combat_particles.spawn(
            CombatParticleKind::WeaponImpact,
            center,
            self.frame,
            Some(source_id),
            intended_target,
        );

        (hits, any_destroyed)
    }

    /// Apply USA Missile Defender residual rocket fire (primary or laser guided secondary).
    ///
    /// Fail-closed: not full SpecialAbilityUpdate prep / LaserBeam attach matrix.
    fn apply_missile_defender_residual_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
        laser_slot: bool,
    ) -> (u32, bool) {
        use crate::game_logic::host_missile_defender::{
            is_legal_missile_defender_splash_target, missile_defender_splash_damage_at,
            MISSILE_DEFENDER_DAMAGE, MISSILE_DEFENDER_FIRE_AUDIO, MISSILE_DEFENDER_SPLASH_RADIUS,
        };

        let damage = source
            .and_then(|sid| self.objects.get(&sid))
            .and_then(|o| {
                if laser_slot {
                    o.secondary_weapon
                        .as_ref()
                        .or(o.weapon.as_ref())
                        .map(|w| w.damage)
                } else {
                    o.weapon.as_ref().map(|w| w.damage)
                }
            })
            .unwrap_or(MISSILE_DEFENDER_DAMAGE);
        let source_team = source
            .and_then(|sid| self.objects.get(&sid).map(|o| o.team))
            .unwrap_or(Team::Neutral);

        let impact_xz = (impact.x, impact.z);
        let mut hits = 0u32;
        let mut any_destroyed = false;
        let mut destroy_ids: Vec<(ObjectId, Option<Team>)> = Vec::new();

        let candidates: Vec<(ObjectId, f32, bool)> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                if source == Some(*id) {
                    return None;
                }
                let combat_kind = obj.is_kind_of(KindOf::Attackable)
                    || obj.is_kind_of(KindOf::Structure)
                    || obj.is_kind_of(KindOf::Infantry)
                    || obj.is_kind_of(KindOf::Vehicle)
                    || obj.is_kind_of(KindOf::Aircraft);
                if !is_legal_missile_defender_splash_target(
                    obj.is_alive(),
                    false,
                    obj.status.under_construction,
                    combat_kind,
                ) {
                    return None;
                }
                let pos = obj.get_position();
                let dist = {
                    let dx = impact_xz.0 - pos.x;
                    let dz = impact_xz.1 - pos.z;
                    (dx * dx + dz * dz).sqrt()
                };
                let is_intended = intended_target == Some(*id);
                if is_intended || dist <= MISSILE_DEFENDER_SPLASH_RADIUS {
                    Some((*id, dist, is_intended))
                } else {
                    None
                }
            })
            .collect();

        for (id, dist, is_intended) in candidates {
            let dmg = missile_defender_splash_damage_at(is_intended, dist, damage);
            if dmg <= 0.0 {
                continue;
            }
            if let Some(obj) = self.objects.get_mut(&id) {
                let destroyed = obj.take_damage_from(dmg, source);
                hits = hits.saturating_add(1);
                if destroyed {
                    any_destroyed = true;
                    destroy_ids.push((id, Some(source_team)));
                }
            }
        }

        for (id, killer) in destroy_ids {
            self.mark_object_for_destruction(id, killer);
        }

        self.missile_defender_residual_fires =
            self.missile_defender_residual_fires.saturating_add(1);
        self.missile_defender_residual_units_hit = self
            .missile_defender_residual_units_hit
            .saturating_add(hits);
        if laser_slot {
            self.missile_defender_residual_laser_fires =
                self.missile_defender_residual_laser_fires.saturating_add(1);
        }

        self.queue_audio_event(
            AudioEventRequest::new(MISSILE_DEFENDER_FIRE_AUDIO)
                .with_position(impact)
                .with_priority(150),
        );
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(impact),
                self.frame,
                sid,
                intended_target,
            );
        }

        (hits, any_destroyed)
    }

    /// Activate Missile Defender laser guided special residual: lock secondary + attack.
    ///
    /// Fail-closed: not full PreparationTime / PersistentPrepTime / LaserBeam object matrix.
    /// SpecialPower ReloadTime = 0 residual (always ready).
    pub fn activate_missile_defender_laser_guided(
        &mut self,
        object_id: ObjectId,
        target_id: ObjectId,
    ) -> bool {
        use crate::game_logic::host_missile_defender::{
            can_activate_laser_guided, is_missile_defender_template, laser_guided_in_start_range,
            LASER_GUIDED_INITIATE_AUDIO,
        };

        let Some(obj) = self.objects.get(&object_id) else {
            return false;
        };
        if !can_activate_laser_guided(
            is_missile_defender_template(&obj.template_name),
            obj.is_alive(),
        ) {
            return false;
        }
        if obj.secondary_weapon.is_none() {
            return false;
        }
        let Some(target) = self.objects.get(&target_id) else {
            return false;
        };
        if !target.is_alive() {
            return false;
        }
        let src_pos = obj.get_position();
        let tgt_pos = target.get_position();
        let dist = {
            let dx = src_pos.x - tgt_pos.x;
            let dz = src_pos.z - tgt_pos.z;
            (dx * dx + dz * dz).sqrt()
        };
        // Retail StartAbilityRange = 200 residual.
        if !laser_guided_in_start_range(dist) {
            return false;
        }

        let src_pos = src_pos;
        if let Some(obj) = self.objects.get_mut(&object_id) {
            obj.active_weapon_slot = 1;
            obj.attack_target(target_id);
        }
        self.missile_defender_residual_laser_specials = self
            .missile_defender_residual_laser_specials
            .saturating_add(1);
        self.queue_audio_event(
            AudioEventRequest::new(LASER_GUIDED_INITIATE_AUDIO)
                .with_object(object_id)
                .with_position(src_pos)
                .with_priority(160),
        );
        true
    }

    /// Record Combat Cycle residual rider load honesty.
    pub fn record_combat_cycle_residual_load(&mut self) {
        self.combat_cycle_residual_loads = self.combat_cycle_residual_loads.saturating_add(1);
    }

    /// Apply residual rider weapon switch to a Combat Cycle (RiderChangeContain residual).
    ///
    /// Fail-closed: not full STATUS_RIDER death OCL / scuttle / stealth matrix.
    pub fn apply_combat_cycle_rider(
        &mut self,
        object_id: ObjectId,
        rider: crate::game_logic::host_combat_cycle::CombatCycleRider,
    ) -> bool {
        use crate::game_logic::host_combat_cycle::{
            combat_cycle_weapon_for_rider, is_combat_cycle_template,
        };
        use crate::game_logic::thing::ThingTemplate;

        let Some(obj) = self.objects.get_mut(&object_id) else {
            return false;
        };
        if !is_combat_cycle_template(&obj.template_name) {
            return false;
        }
        if !obj.is_combat_cycle_style_container() {
            obj.install_combat_cycle_transport();
        }

        obj.combat_cycle_rider = rider.as_u8();
        if let Some(name) =
            crate::game_logic::host_combat_cycle::combat_cycle_weapon_name_for_rider(rider)
        {
            let mut weapon = ThingTemplate::weapon_from_store(name)
                .or_else(|| combat_cycle_weapon_for_rider(rider));
            if let Some(ref mut w) = weapon {
                // Force residual stats from host residual table.
                if let Some(stats) = combat_cycle_weapon_for_rider(rider) {
                    w.damage = stats.damage;
                    w.range = stats.range;
                    w.min_range = stats.min_range;
                    w.reload_time = stats.reload_time;
                    w.can_target_air = stats.can_target_air;
                    w.can_target_ground = stats.can_target_ground;
                    w.projectile_speed = stats.projectile_speed;
                    w.ammo = stats.ammo;
                }
            }
            obj.weapon = weapon;
        } else {
            obj.weapon = None;
            obj.secondary_weapon = None;
        }

        self.combat_cycle_residual_rider_switches =
            self.combat_cycle_residual_rider_switches.saturating_add(1);
        true
    }

    /// Refresh Combat Cycle weapon from current occupant residual.
    ///
    /// Empty bike → PRIMARY NONE; single rider → rider weapon residual.
    pub fn refresh_combat_cycle_rider_weapon(&mut self, container_id: ObjectId) {
        use crate::game_logic::host_combat_cycle::{
            combat_cycle_weapon_for_rider, is_combat_cycle_template, rider_from_template_name,
            CombatCycleRider,
        };

        let Some(container) = self.objects.get(&container_id) else {
            return;
        };
        if !is_combat_cycle_template(&container.template_name)
            && !container.is_combat_cycle_style_container()
        {
            return;
        }
        let occupants = container.contained_units();
        let rider = if let Some(first) = occupants.first() {
            self.objects
                .get(first)
                .map(|o| rider_from_template_name(&o.template_name))
                .unwrap_or(CombatCycleRider::None)
        } else if container.combat_cycle_rider > 0 {
            // Spawn InitialPayload residual without a live occupant object:
            // keep current rider class when no occupants tracked yet.
            CombatCycleRider::from_u8(container.combat_cycle_rider)
        } else {
            CombatCycleRider::None
        };

        // When occupants present, force rider from them; when empty and no
        // spawn residual, clear weapon.
        let rider = if occupants.is_empty() && container.combat_cycle_rider == 0 {
            CombatCycleRider::None
        } else if !occupants.is_empty() {
            rider
        } else {
            // Occupants empty but spawn rider still set: keep spawn residual.
            CombatCycleRider::from_u8(container.combat_cycle_rider)
        };

        let _ = combat_cycle_weapon_for_rider(rider);
        let _ = self.apply_combat_cycle_rider(container_id, rider);
    }

    /// Apply Combat Cycle residual fire (rider weapon or suicide area).
    fn apply_combat_cycle_residual_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
    ) -> (u32, bool) {
        use crate::game_logic::host_combat_cycle::{
            combat_cycle_audio_for_rider, is_legal_combat_cycle_target, is_terrorist_suicide_rider,
            rpg_splash_damage_at, suicide_bike_damage_at, CombatCycleRider, RPG_DAMAGE, RPG_SPLASH,
            SUICIDE_SECONDARY_RADIUS,
        };

        let (source_team, rider, bike_pos) = source
            .and_then(|sid| {
                self.objects.get(&sid).map(|o| {
                    (
                        o.team,
                        CombatCycleRider::from_u8(o.combat_cycle_rider),
                        o.get_position(),
                    )
                })
            })
            .unwrap_or((Team::Neutral, CombatCycleRider::None, impact));

        // Infer rebel when rider unset but weapon residual looks like MG.
        let rider = if matches!(rider, CombatCycleRider::None) {
            if let Some(sid) = source {
                if let Some(o) = self.objects.get(&sid) {
                    if let Some(w) = o.weapon.as_ref() {
                        if (w.damage - 8.0).abs() < 0.5 {
                            CombatCycleRider::Rebel
                        } else if (w.damage - 40.0).abs() < 0.5 {
                            CombatCycleRider::TunnelDefender
                        } else if (w.damage - 180.0).abs() < 1.0 {
                            CombatCycleRider::JarmenKell
                        } else if w.damage >= 500.0 {
                            CombatCycleRider::Terrorist
                        } else {
                            rider
                        }
                    } else {
                        rider
                    }
                } else {
                    rider
                }
            } else {
                rider
            }
        } else {
            rider
        };

        let mut hits = 0u32;
        let mut any_destroyed = false;
        let mut destroy_ids: Vec<(ObjectId, Option<Team>)> = Vec::new();
        let mut destroy_self = false;

        if is_terrorist_suicide_rider(rider) {
            // SuicideBikeBomb residual around bike position.
            let center = bike_pos;
            let candidates: Vec<(ObjectId, f32)> = self
                .objects
                .iter()
                .filter_map(|(id, obj)| {
                    if source == Some(*id) {
                        return None;
                    }
                    let combat_kind = obj.is_kind_of(KindOf::Attackable)
                        || obj.is_kind_of(KindOf::Structure)
                        || obj.is_kind_of(KindOf::Infantry)
                        || obj.is_kind_of(KindOf::Vehicle)
                        || obj.is_kind_of(KindOf::Aircraft);
                    if !is_legal_combat_cycle_target(
                        obj.is_alive(),
                        false,
                        obj.status.under_construction,
                        combat_kind,
                    ) {
                        return None;
                    }
                    let pos = obj.get_position();
                    let dist = {
                        let dx = center.x - pos.x;
                        let dz = center.z - pos.z;
                        (dx * dx + dz * dz).sqrt()
                    };
                    if dist <= SUICIDE_SECONDARY_RADIUS {
                        Some((*id, dist))
                    } else {
                        None
                    }
                })
                .collect();

            for (id, dist) in candidates {
                let dmg = suicide_bike_damage_at(dist);
                if dmg <= 0.0 {
                    continue;
                }
                if let Some(obj) = self.objects.get_mut(&id) {
                    let destroyed = obj.take_damage_from(dmg, source);
                    hits = hits.saturating_add(1);
                    if destroyed {
                        any_destroyed = true;
                        destroy_ids.push((id, Some(source_team)));
                    }
                }
            }
            destroy_self = true;
            self.combat_cycle_residual_suicides =
                self.combat_cycle_residual_suicides.saturating_add(1);
        } else if matches!(rider, CombatCycleRider::TunnelDefender) {
            // RPG splash residual.
            let impact_xz = (impact.x, impact.z);
            let candidates: Vec<(ObjectId, f32, bool)> = self
                .objects
                .iter()
                .filter_map(|(id, obj)| {
                    if source == Some(*id) {
                        return None;
                    }
                    let combat_kind = obj.is_kind_of(KindOf::Attackable)
                        || obj.is_kind_of(KindOf::Structure)
                        || obj.is_kind_of(KindOf::Infantry)
                        || obj.is_kind_of(KindOf::Vehicle)
                        || obj.is_kind_of(KindOf::Aircraft);
                    if !is_legal_combat_cycle_target(
                        obj.is_alive(),
                        false,
                        obj.status.under_construction,
                        combat_kind,
                    ) {
                        return None;
                    }
                    let pos = obj.get_position();
                    let dist = {
                        let dx = impact_xz.0 - pos.x;
                        let dz = impact_xz.1 - pos.z;
                        (dx * dx + dz * dz).sqrt()
                    };
                    let is_intended = intended_target == Some(*id);
                    if is_intended || dist <= RPG_SPLASH {
                        Some((*id, dist, is_intended))
                    } else {
                        None
                    }
                })
                .collect();

            for (id, dist, is_intended) in candidates {
                let dmg = rpg_splash_damage_at(is_intended, dist);
                if dmg <= 0.0 {
                    continue;
                }
                if let Some(obj) = self.objects.get_mut(&id) {
                    let destroyed = obj.take_damage_from(dmg, source);
                    hits = hits.saturating_add(1);
                    if destroyed {
                        any_destroyed = true;
                        destroy_ids.push((id, Some(source_team)));
                    }
                }
            }
            let _ = RPG_DAMAGE;
        } else {
            // Direct residual hit (Rebel MG / Kell sniper).
            if let Some(tid) = intended_target {
                let dmg = source
                    .and_then(|sid| self.objects.get(&sid))
                    .and_then(|o| o.weapon.as_ref())
                    .map(|w| w.damage)
                    .unwrap_or(0.0);
                if dmg > 0.0 {
                    if let Some(obj) = self.objects.get_mut(&tid) {
                        if is_legal_combat_cycle_target(
                            obj.is_alive(),
                            false,
                            obj.status.under_construction,
                            true,
                        ) {
                            let destroyed = obj.take_damage_from(dmg, source);
                            hits = hits.saturating_add(1);
                            if destroyed {
                                any_destroyed = true;
                                destroy_ids.push((tid, Some(source_team)));
                            }
                        }
                    }
                }
            }
        }

        for (id, killer) in destroy_ids {
            self.mark_object_for_destruction(id, killer);
        }
        if destroy_self {
            if let Some(sid) = source {
                self.mark_object_for_destruction(sid, Some(source_team));
            }
        }

        self.combat_cycle_residual_fires = self.combat_cycle_residual_fires.saturating_add(1);
        self.combat_cycle_residual_units_hit =
            self.combat_cycle_residual_units_hit.saturating_add(hits);

        if let Some(audio) = combat_cycle_audio_for_rider(rider) {
            self.queue_audio_event(
                AudioEventRequest::new(audio)
                    .with_position(impact)
                    .with_priority(150),
            );
        }
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(impact),
                self.frame,
                sid,
                intended_target,
            );
        }

        (hits, any_destroyed)
    }

    /// Apply Toxin Tractor primary stream residual (poison damage radius).
    fn apply_toxin_tractor_stream_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        intended_target: Option<ObjectId>,
        source_team: Team,
    ) -> (u32, bool) {
        use crate::game_logic::host_toxin_tractor::{
            anthrax_tier_from_flags, is_chem_general_template, is_legal_toxin_target,
            toxin_stream_damage, toxin_stream_damage_at, AnthraxResidualTier,
            ToxinTractorSalvageTier, TOXIN_STREAM_AUDIO, TOXIN_STREAM_RADIUS,
            UPGRADE_GLA_ANTHRAX_BETA, UPGRADE_GLA_ANTHRAX_GAMMA, UPGRADE_GLA_ANTHRAX_GAMMA_ALT,
        };

        let (anthrax, tier) = source
            .and_then(|sid| self.objects.get(&sid))
            .map(|a| {
                let has_gamma = a.has_upgrade_tag(UPGRADE_GLA_ANTHRAX_GAMMA)
                    || a.has_upgrade_tag(UPGRADE_GLA_ANTHRAX_GAMMA_ALT)
                    || a.has_upgrade_tag("Chem_Upgrade_GLAAnthraxGamma")
                    || a.has_upgrade_tag("Upgrade_GLAAnthraxGamma");
                let has_beta = a.has_upgrade_tag(UPGRADE_GLA_ANTHRAX_BETA)
                    || a.has_upgrade_tag("Upgrade_GLAAnthraxBeta");
                let anthrax = anthrax_tier_from_flags(
                    has_gamma,
                    has_beta,
                    is_chem_general_template(&a.template_name),
                );
                let tier = if a.has_upgrade_tag("WEAPONSET_CRATEUPGRADE_TWO") {
                    ToxinTractorSalvageTier::Two
                } else if a.has_upgrade_tag("WEAPONSET_CRATEUPGRADE_ONE") {
                    ToxinTractorSalvageTier::One
                } else {
                    ToxinTractorSalvageTier::Base
                };
                (anthrax, tier)
            })
            .unwrap_or((AnthraxResidualTier::None, ToxinTractorSalvageTier::Base));
        let base_dmg = toxin_stream_damage(tier, anthrax);
        let impact_xz = (impact.x, impact.z);
        let mut hits = 0u32;
        let mut any_destroyed = false;
        let mut destroy_ids: Vec<(ObjectId, Option<Team>)> = Vec::new();

        let candidates: Vec<(ObjectId, f32, bool)> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                if source == Some(*id) {
                    return None;
                }
                let combat_kind = obj.is_kind_of(KindOf::Attackable)
                    || obj.is_kind_of(KindOf::Structure)
                    || obj.is_kind_of(KindOf::Infantry)
                    || obj.is_kind_of(KindOf::Vehicle);
                let airborne = obj.is_kind_of(KindOf::Aircraft) || obj.status.airborne_target;
                if !is_legal_toxin_target(
                    obj.is_alive(),
                    false,
                    obj.status.under_construction,
                    combat_kind,
                    airborne,
                ) {
                    return None;
                }
                let pos = obj.get_position();
                let dist = {
                    let dx = impact_xz.0 - pos.x;
                    let dz = impact_xz.1 - pos.z;
                    (dx * dx + dz * dz).sqrt()
                };
                let is_intended = intended_target == Some(*id);
                // Stream residual: intended always; others within PrimaryDamageRadius.
                if is_intended || dist <= TOXIN_STREAM_RADIUS {
                    Some((*id, dist, is_intended))
                } else {
                    None
                }
            })
            .collect();

        for (id, dist, is_intended) in candidates {
            let dmg = if is_intended {
                base_dmg
            } else {
                toxin_stream_damage_at(dist, base_dmg)
            };
            if dmg <= 0.0 {
                continue;
            }
            if let Some(obj) = self.objects.get_mut(&id) {
                let destroyed = obj.take_damage_from(dmg, source);
                hits = hits.saturating_add(1);
                if destroyed {
                    any_destroyed = true;
                    destroy_ids.push((id, Some(source_team)));
                }
            }
        }

        for (id, killer) in destroy_ids {
            self.mark_object_for_destruction(id, killer);
        }

        self.toxin_tractor.record_stream_fire(hits);
        if anthrax.is_gamma() {
            self.toxin_tractor.record_gamma_stream_fire();
        }
        self.queue_audio_event(
            AudioEventRequest::new(TOXIN_STREAM_AUDIO)
                .with_position(impact)
                .with_priority(150),
        );
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(impact),
                self.frame,
                sid,
                intended_target,
            );
        }

        (hits, any_destroyed)
    }

    /// Apply Toxin Tractor contaminate spray residual + MediumPoisonField spawn.
    fn apply_toxin_tractor_spray_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
        source_team: Team,
    ) -> (u32, bool) {
        use crate::game_logic::host_toxin_tractor::{
            anthrax_tier_from_flags, is_chem_general_template, is_legal_toxin_target,
            toxin_spray_damage, toxin_spray_damage_at, AnthraxResidualTier, TOXIN_POISON_AUDIO,
            TOXIN_SPRAY_AUDIO, TOXIN_SPRAY_RADIUS, UPGRADE_GLA_ANTHRAX_BETA,
            UPGRADE_GLA_ANTHRAX_GAMMA, UPGRADE_GLA_ANTHRAX_GAMMA_ALT,
        };

        let anthrax = source
            .and_then(|sid| {
                self.objects.get(&sid).map(|a| {
                    let has_gamma = a.has_upgrade_tag(UPGRADE_GLA_ANTHRAX_GAMMA)
                        || a.has_upgrade_tag(UPGRADE_GLA_ANTHRAX_GAMMA_ALT)
                        || a.has_upgrade_tag("Chem_Upgrade_GLAAnthraxGamma")
                        || a.has_upgrade_tag("Upgrade_GLAAnthraxGamma");
                    let has_beta = a.has_upgrade_tag(UPGRADE_GLA_ANTHRAX_BETA)
                        || a.has_upgrade_tag("Upgrade_GLAAnthraxBeta");
                    anthrax_tier_from_flags(
                        has_gamma,
                        has_beta,
                        is_chem_general_template(&a.template_name),
                    )
                })
            })
            .unwrap_or(AnthraxResidualTier::None);
        let spray_dmg = toxin_spray_damage(anthrax);
        // Spray residual originates at the tractor; impact is attack target.
        // Fail-closed residual: use impact as field center (contaminate puddle).
        let center = source
            .and_then(|sid| self.objects.get(&sid).map(|o| o.get_position()))
            .unwrap_or(impact);
        let center_xz = (center.x, center.z);
        let mut hits = 0u32;
        let mut any_destroyed = false;
        let mut destroy_ids: Vec<(ObjectId, Option<Team>)> = Vec::new();

        let candidates: Vec<(ObjectId, f32)> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                if source == Some(*id) {
                    return None;
                }
                let combat_kind = obj.is_kind_of(KindOf::Attackable)
                    || obj.is_kind_of(KindOf::Structure)
                    || obj.is_kind_of(KindOf::Infantry)
                    || obj.is_kind_of(KindOf::Vehicle);
                let airborne = obj.is_kind_of(KindOf::Aircraft) || obj.status.airborne_target;
                if !is_legal_toxin_target(
                    obj.is_alive(),
                    false,
                    obj.status.under_construction,
                    combat_kind,
                    airborne,
                ) {
                    return None;
                }
                let pos = obj.get_position();
                let dist = {
                    let dx = center_xz.0 - pos.x;
                    let dz = center_xz.1 - pos.z;
                    (dx * dx + dz * dz).sqrt()
                };
                if dist <= TOXIN_SPRAY_RADIUS {
                    Some((*id, dist))
                } else {
                    None
                }
            })
            .collect();

        for (id, dist) in candidates {
            let dmg = toxin_spray_damage_at(dist, spray_dmg);
            if dmg <= 0.0 {
                continue;
            }
            if let Some(obj) = self.objects.get_mut(&id) {
                let destroyed = obj.take_damage_from(dmg, source);
                hits = hits.saturating_add(1);
                if destroyed {
                    any_destroyed = true;
                    destroy_ids.push((id, Some(source_team)));
                }
            }
        }

        for (id, killer) in destroy_ids {
            self.mark_object_for_destruction(id, killer);
        }

        // MediumPoisonField residual at contaminate puddle (fail-closed vs MinShots=4).
        let source_id = source.unwrap_or(ObjectId(0));
        let _ = self.toxin_tractor.spawn_medium_field(
            source_id,
            source_team,
            center,
            self.frame,
            anthrax,
        );
        self.toxin_tractor.record_spray_fire(hits);

        self.queue_audio_event(
            AudioEventRequest::new(TOXIN_SPRAY_AUDIO)
                .with_position(center)
                .with_priority(150),
        );
        self.queue_audio_event(
            AudioEventRequest::new(TOXIN_POISON_AUDIO)
                .with_position(center)
                .with_priority(140),
        );
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                center,
                Some(impact),
                self.frame,
                sid,
                None,
            );
        }

        (hits, any_destroyed)
    }

    /// Advance Toxin Tractor poison field residual zones (medium spray + small death).
    fn update_toxin_tractor_poison_zones(&mut self) {
        let object_positions: Vec<(ObjectId, Vec3, Team, bool, bool)> = self
            .objects
            .iter()
            .map(|(id, obj)| {
                (
                    *id,
                    obj.get_position(),
                    obj.team,
                    obj.is_alive(),
                    obj.is_kind_of(KindOf::Aircraft) || obj.status.airborne_target,
                )
            })
            .collect();

        let plans = self
            .toxin_tractor
            .plan_due_ticks(self.frame, &object_positions);
        let frame = self.frame;

        for plan in plans {
            let mut total_damage = 0.0_f32;
            let mut applications = 0_u32;
            let mut destroyed = 0_u32;
            let mut destroy_ids: Vec<(ObjectId, Team)> = Vec::new();

            for hit in &plan.hits {
                if let Some(target) = self.objects.get_mut(&hit.target_id) {
                    if !target.is_alive() {
                        continue;
                    }
                    let killed = target.take_damage_from(hit.damage, None);
                    total_damage += hit.damage;
                    applications += 1;
                    if killed {
                        destroyed += 1;
                        destroy_ids.push((hit.target_id, plan.source_team));
                    }
                }
            }

            for (id, killer_team) in destroy_ids {
                self.mark_object_for_destruction(id, Some(killer_team));
            }

            self.toxin_tractor.record_tick_complete(
                plan.zone_id,
                total_damage,
                applications,
                destroyed,
                frame,
            );
        }

        self.toxin_tractor.prune_expired(frame);
    }

    /// Apply ComancheRocketPodWeapon area residual at impact.
    ///
    /// Returns (units_hit, any_destroyed).
    /// Fail-closed: not full ScatterTarget clip pattern / projectile flight.
    fn apply_comanche_rocket_pod_area_at(
        &mut self,
        impact: Vec3,
        source: Option<ObjectId>,
    ) -> (u32, bool) {
        use crate::game_logic::host_comanche_rocket_pods::{
            is_legal_rocket_pod_splash_target, rocket_pod_damage_at_distance, ROCKET_POD_AUDIO,
            ROCKET_POD_SECONDARY_RADIUS,
        };

        let impact_xz = (impact.x, impact.z);
        let mut hits = 0u32;
        let mut any_destroyed = false;
        let mut destroy_ids: Vec<(ObjectId, Option<Team>)> = Vec::new();
        let source_team = source.and_then(|id| self.objects.get(&id).map(|o| o.team));

        let candidates: Vec<(ObjectId, f32)> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                if source == Some(*id) {
                    return None;
                }
                let combat_kind = obj.is_kind_of(KindOf::Attackable)
                    || obj.is_kind_of(KindOf::Structure)
                    || obj.is_kind_of(KindOf::Infantry)
                    || obj.is_kind_of(KindOf::Vehicle)
                    || obj.is_kind_of(KindOf::Aircraft);
                if !is_legal_rocket_pod_splash_target(
                    obj.is_alive(),
                    false,
                    obj.status.under_construction,
                    combat_kind,
                ) {
                    return None;
                }
                let pos = obj.get_position();
                let dist = {
                    let dx = impact_xz.0 - pos.x;
                    let dz = impact_xz.1 - pos.z;
                    (dx * dx + dz * dz).sqrt()
                };
                if dist <= ROCKET_POD_SECONDARY_RADIUS {
                    Some((*id, dist))
                } else {
                    None
                }
            })
            .collect();

        for (id, dist) in candidates {
            let dmg = rocket_pod_damage_at_distance(dist);
            if dmg <= 0.0 {
                continue;
            }
            if let Some(obj) = self.objects.get_mut(&id) {
                let destroyed = obj.take_damage_from(dmg, source);
                hits = hits.saturating_add(1);
                if destroyed {
                    any_destroyed = true;
                    destroy_ids.push((id, source_team));
                }
            }
        }

        for (id, killer) in destroy_ids {
            self.mark_object_for_destruction(id, killer);
        }

        self.comanche_rocket_pod_residual_area_attacks = self
            .comanche_rocket_pod_residual_area_attacks
            .saturating_add(1);
        self.comanche_rocket_pod_residual_units_hit = self
            .comanche_rocket_pod_residual_units_hit
            .saturating_add(hits);

        self.queue_audio_event(
            AudioEventRequest::new(ROCKET_POD_AUDIO)
                .with_position(impact)
                .with_priority(150),
        );
        if let Some(sid) = source {
            let _ = self.combat_particles.spawn_weapon_fire_fx(
                self.objects
                    .get(&sid)
                    .map(|o| o.get_position())
                    .unwrap_or(impact),
                Some(impact),
                self.frame,
                sid,
                None,
            );
        }

        (hits, any_destroyed)
    }

    /// Residual Sentry Drone auto-fire: gun-equipped Sentry acquires nearest enemy
    /// in weapon range and deals damage without a manual AttackObject order.
    /// Fail-closed: not full DeployStyleAIUpdate pack/unpack / LOS matrix.
    fn try_sentry_drone_residual_fire(&mut self, sentry_id: ObjectId) {
        use crate::game_logic::host_sentry_drone::{
            is_legal_sentry_auto_fire_target, SENTRY_GUN_AUDIO,
        };

        let current_time = self.frame as f32 * LOGIC_FRAME_TIMESTEP;

        let Some(attacker) = self.objects.get(&sentry_id) else {
            return;
        };
        if !attacker.is_alive() || attacker.weapon.is_none() || !attacker.can_attack() {
            return;
        }
        let Some(weapon) = attacker.weapon.as_ref() else {
            return;
        };
        if !Object::weapon_ready(weapon, current_time) {
            return;
        }

        let team = attacker.team;
        let range = weapon.range;
        let damage = weapon.damage;
        let fire_pos = attacker.get_position();

        let mut best: Option<(ObjectId, f32)> = None;
        for (id, obj) in &self.objects {
            if *id == sentry_id {
                continue;
            }
            let combat_kind = obj.is_kind_of(KindOf::Attackable)
                || obj.is_kind_of(KindOf::Structure)
                || obj.is_kind_of(KindOf::Infantry)
                || obj.is_kind_of(KindOf::Vehicle)
                || obj.is_kind_of(KindOf::Aircraft);
            let stealthed_hidden = obj.is_effectively_stealthed() && obj.team != team;
            if !is_legal_sentry_auto_fire_target(
                obj.is_alive(),
                obj.team == team,
                obj.team == Team::Neutral,
                obj.status.under_construction,
                combat_kind,
                stealthed_hidden,
            ) {
                continue;
            }
            let dist = fire_pos.distance(obj.get_position());
            if dist <= range && best.map(|(_, d)| dist < d).unwrap_or(true) {
                best = Some((*id, dist));
            }
        }

        let Some((target_id, _)) = best else {
            return;
        };

        let mut destroyed = false;
        let mut kill_xp = 0.0;
        if let Some(target) = self.objects.get_mut(&target_id) {
            destroyed = target.take_damage(damage);
            if destroyed {
                kill_xp = target.thing.template.experience_value
                    * Self::veterancy_xp_multiplier(target.experience.level);
            }
        }

        if let Some(attacker) = self.objects.get_mut(&sentry_id) {
            if let Some(w) = attacker.weapon.as_mut() {
                w.last_fire_time = current_time;
            }
            attacker.target = Some(target_id);
            attacker.target_location = None;
            attacker.force_attack = false;
            attacker.ai_state = AIState::Attacking;
            attacker.status.attacking = true;
            // STEALTH_NOT_WHILE_ATTACKING residual.
            if attacker.stealth_breaks_on_attack && attacker.status.stealthed {
                attacker.break_stealth();
            }
            if destroyed {
                attacker.gain_experience(kill_xp);
                attacker.stop_attack();
            }
        }

        if destroyed {
            self.mark_object_for_destruction(target_id, Some(team));
        }

        let muzzle_pos = self
            .objects
            .get(&sentry_id)
            .map(|a| a.get_position())
            .unwrap_or(fire_pos);
        let impact_pos = self.objects.get(&target_id).map(|t| t.get_position());
        let _ = self.combat_particles.spawn_weapon_fire_fx(
            muzzle_pos,
            impact_pos,
            self.frame,
            sentry_id,
            Some(target_id),
        );
        self.queue_audio_event(
            AudioEventRequest::new(SENTRY_GUN_AUDIO)
                .with_object(sentry_id)
                .with_position(muzzle_pos)
                .with_priority(160),
        );

        self.sentry_drone_residual_auto_fires =
            self.sentry_drone_residual_auto_fires.saturating_add(1);
    }

