    /// Host bunker-buster residual registry (tests / HUD honesty).
    pub fn bunker_buster_residual(
        &self,
    ) -> &crate::game_logic::host_bunker_buster::HostBunkerBusterRegistry {
        &self.bunker_buster
    }

    /// Apply BunkerBuster residual to a structure target:
    /// kill all garrisoned occupants + amplified structure damage vs bunkers.
    ///
    /// Returns (occupants_killed, structure_damage_applied, structure_destroyed).
    /// Fail-closed: not full BunkerBusterBehavior FX / seismic / temp shockwave weapon.
    fn apply_bunker_buster_to_target(
        &mut self,
        target_id: ObjectId,
        attacker_team: Team,
        base_weapon_damage: f32,
    ) -> (u32, f32, bool) {
        use crate::game_logic::host_bunker_buster::{
            bunker_buster_structure_damage, is_bunker_structure_name, BUNKER_BUSTER_AUDIO,
            BUNKER_BUSTER_OCCUPANT_DAMAGE,
        };

        let (occupants, is_bunker, target_pos) = {
            let Some(target) = self.objects.get(&target_id) else {
                return (0, 0.0, false);
            };
            let occ = target.contained_units();
            let bunker = is_bunker_structure_name(&target.template_name)
                || target
                    .building_data
                    .as_ref()
                    .map(|b| {
                        matches!(
                            b.building_type,
                            crate::game_logic::buildings::BuildingType::Bunker
                        ) || b.max_garrison > 0
                    })
                    .unwrap_or(false);
            (occ, bunker, target.get_position())
        };
        let had_occupants = !occupants.is_empty();
        let mut kills = 0u32;
        let mut destroy_ids: Vec<ObjectId> = Vec::new();

        // Remove occupants from container bookkeeping first.
        if let Some(target) = self.objects.get_mut(&target_id) {
            for &occ_id in &occupants {
                target.remove_occupant(occ_id);
            }
        }

        for occ_id in occupants {
            let Some(occ) = self.objects.get_mut(&occ_id) else {
                continue;
            };
            if !occ.is_alive() {
                continue;
            }
            occ.contained_by = None;
            occ.ai_state = AIState::Idle;
            // Residual occupant damage (BunkerBusterAntiTunnel ~400) — lethal for infantry.
            let _ = occ.take_damage(BUNKER_BUSTER_OCCUPANT_DAMAGE.max(occ.health.current * 10.0));
            if !occ.is_alive() || occ.health.current <= 0.0 || occ.status.destroyed {
                kills = kills.saturating_add(1);
                destroy_ids.push(occ_id);
            } else {
                let _ = occ.take_damage(999_999.0);
                kills = kills.saturating_add(1);
                destroy_ids.push(occ_id);
            }
        }

        for id in destroy_ids {
            self.mark_object_for_destruction(id, Some(attacker_team));
        }

        let structure_dmg =
            bunker_buster_structure_damage(base_weapon_damage, is_bunker, had_occupants);
        let mut destroyed = false;
        if let Some(target) = self.objects.get_mut(&target_id) {
            destroyed = target.take_damage(structure_dmg);
            if destroyed {
                self.mark_object_for_destruction(target_id, Some(attacker_team));
            }
        }

        self.bunker_buster.record_bunker_buster_blast(
            kills,
            structure_dmg,
            is_bunker && structure_dmg > base_weapon_damage + 0.01,
        );

        self.queue_audio_event(
            AudioEventRequest::new(BUNKER_BUSTER_AUDIO)
                .with_position(target_pos)
                .with_priority(160),
        );

        (kills, structure_dmg, destroyed)
    }

    /// Apply KILL_GARRISONED residual: kill `floor(damage)` garrisoned occupants.
    /// Fail-closed: no structure HP damage (C++ ActiveBody KillGarrisoned path).
    fn apply_kill_garrisoned_to_target(
        &mut self,
        target_id: ObjectId,
        attacker_team: Team,
        damage_amount: f32,
    ) -> u32 {
        use crate::game_logic::host_bunker_buster::{
            kill_garrisoned_count, BUNKER_BUSTER_OCCUPANT_DAMAGE,
        };

        let occupants = self
            .objects
            .get(&target_id)
            .map(|t| t.contained_units())
            .unwrap_or_default();
        let kill_n = kill_garrisoned_count(damage_amount, occupants.len());
        if kill_n == 0 {
            return 0;
        }

        let to_kill: Vec<ObjectId> = occupants.into_iter().take(kill_n).collect();
        if let Some(target) = self.objects.get_mut(&target_id) {
            for &occ_id in &to_kill {
                target.remove_occupant(occ_id);
            }
        }

        let mut kills = 0u32;
        let mut destroy_ids: Vec<ObjectId> = Vec::new();
        for occ_id in to_kill {
            let Some(occ) = self.objects.get_mut(&occ_id) else {
                continue;
            };
            if !occ.is_alive() {
                continue;
            }
            occ.contained_by = None;
            occ.ai_state = AIState::Idle;
            let _ = occ.take_damage(BUNKER_BUSTER_OCCUPANT_DAMAGE.max(occ.health.current * 10.0));
            if !occ.is_alive() || occ.health.current <= 0.0 || occ.status.destroyed {
                kills = kills.saturating_add(1);
                destroy_ids.push(occ_id);
            } else {
                let _ = occ.take_damage(999_999.0);
                kills = kills.saturating_add(1);
                destroy_ids.push(occ_id);
            }
        }
        for id in destroy_ids {
            self.mark_object_for_destruction(id, Some(attacker_team));
        }

        self.bunker_buster.record_kill_garrisoned(kills);
        kills
    }

    /// Apply NeutronBlast residual at world impact: kill infantry + unman vehicles
    /// in blast radius. Returns (infantry_kills, vehicles_unmanned, vehicle_kills).
    ///
    /// Fail-closed: not full AffectAirborne / ally Relationship matrix.
    fn apply_neutron_blast_at(
        &mut self,
        impact: glam::Vec3,
        caster_team: Team,
        caster_id: Option<ObjectId>,
        affect_allies: bool,
    ) -> (u32, u32, u32) {
        use crate::game_logic::host_neutron_shell::{
            in_neutron_blast_radius_2d, is_legal_neutron_blast_target, neutron_effect_for_target,
            NeutronEffect, HOST_NEUTRON_BLAST_RADIUS, NEUTRON_SHELL_AUDIO,
        };

        let center = (impact.x, impact.z);
        let radius = HOST_NEUTRON_BLAST_RADIUS;
        let mut infantry_kills = 0u32;
        let mut vehicles_unmanned = 0u32;
        let mut vehicle_kills = 0u32;
        let mut destroy_ids: Vec<ObjectId> = Vec::new();

        let candidates: Vec<ObjectId> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                if caster_id == Some(*id) {
                    return None;
                }
                if !obj.is_alive() {
                    return None;
                }
                let pos = obj.get_position();
                if !in_neutron_blast_radius_2d(center, (pos.x, pos.z), radius) {
                    return None;
                }
                let same_team = obj.team == caster_team;
                if !is_legal_neutron_blast_target(
                    obj.is_alive(),
                    obj.is_kind_of(KindOf::Infantry),
                    obj.is_kind_of(KindOf::Vehicle),
                    obj.is_kind_of(KindOf::Aircraft),
                    obj.is_kind_of(KindOf::Structure),
                    false, // drone residual not modeled on host KindOf
                    obj.status.airborne_target,
                    false, // AffectAirborne = No for NeutronCannonShell residual
                    same_team,
                    affect_allies,
                ) {
                    return None;
                }
                Some(*id)
            })
            .collect();

        for id in candidates {
            let Some(obj) = self.objects.get_mut(&id) else {
                continue;
            };
            let effect = neutron_effect_for_target(
                obj.is_kind_of(KindOf::Infantry),
                obj.is_kind_of(KindOf::Vehicle),
                false,
                &obj.template_name,
            );
            match effect {
                NeutronEffect::KillInfantry => {
                    // Residual: kill infantry (take full health damage).
                    let _ = obj.take_damage(obj.health.current.max(1.0) * 10.0);
                    if !obj.is_alive() || obj.health.current <= 0.0 {
                        infantry_kills = infantry_kills.saturating_add(1);
                        destroy_ids.push(id);
                    } else {
                        // Force kill residual.
                        let _ = obj.take_damage(999_999.0);
                        infantry_kills = infantry_kills.saturating_add(1);
                        destroy_ids.push(id);
                    }
                }
                NeutronEffect::UnmanVehicle => {
                    obj.apply_kill_pilot_unmanned();
                    // C++ NeutronBlastBehavior: setTeam(neutral) residual.
                    obj.team = Team::Neutral;
                    vehicles_unmanned = vehicles_unmanned.saturating_add(1);
                }
                NeutronEffect::KillVehicle => {
                    let _ = obj.take_damage(obj.health.current.max(1.0) * 10.0);
                    vehicle_kills = vehicle_kills.saturating_add(1);
                    destroy_ids.push(id);
                }
                NeutronEffect::None => {}
            }
        }

        for id in destroy_ids {
            self.mark_object_for_destruction(id, Some(caster_team));
        }

        self.neutron_shell_residual_blasts = self.neutron_shell_residual_blasts.saturating_add(1);
        self.neutron_shell_residual_infantry_kills = self
            .neutron_shell_residual_infantry_kills
            .saturating_add(infantry_kills);
        self.neutron_shell_residual_vehicles_unmanned = self
            .neutron_shell_residual_vehicles_unmanned
            .saturating_add(vehicles_unmanned);

        self.queue_audio_event(
            AudioEventRequest::new(NEUTRON_SHELL_AUDIO)
                .with_position(impact)
                .with_priority(155),
        );
        let _ = self.combat_particles.spawn_weapon_fire_fx(
            impact,
            Some(impact),
            self.frame,
            caster_id.unwrap_or(ObjectId(0)),
            None,
        );

        (infantry_kills, vehicles_unmanned, vehicle_kills)
    }

    /// Residual fire-from-transport: docked passengers auto-engage nearest
    /// enemy in weapon range from the **container position** when the container
    /// has `passengers_allowed_to_fire` (Battle Bus / Combat Chinook / Humvee residual).
    /// Fail-closed: not C++ transport weapon bone positions / multi-slot matrix.
    fn try_transport_passenger_residual_fire(&mut self, passenger_id: ObjectId) {
        let current_time = self.frame as f32 * LOGIC_FRAME_TIMESTEP;

        let Some(attacker) = self.objects.get(&passenger_id) else {
            return;
        };
        if !attacker.is_alive() || attacker.weapon.is_none() {
            return;
        }
        let Some(weapon) = attacker.weapon.as_ref() else {
            return;
        };
        if !Object::weapon_ready(weapon, current_time) {
            return;
        }

        let container_id = attacker.container_id();
        let Some(cid) = container_id else {
            return;
        };
        let Some(container) = self.objects.get(&cid) else {
            return;
        };
        // C++ OpenContain::isPassengerAllowedToFire residual.
        if !container.passengers_allowed_to_fire {
            return;
        }
        let is_battle_bus = container.is_battle_bus_style_container();
        let is_combat_chinook = container.is_combat_chinook_style_container();
        let is_listening_outpost = container.is_listening_outpost_style_container();
        let team = attacker.team;
        let range = weapon.range;
        let damage = weapon.damage;
        let fire_pos = container.get_position();

        let mut best: Option<(ObjectId, f32)> = None;
        for (id, obj) in &self.objects {
            if *id == passenger_id || *id == cid {
                continue;
            }
            if !obj.is_alive() || obj.team == team || obj.team == Team::Neutral {
                continue;
            }
            if !obj.is_kind_of(KindOf::Attackable)
                && !obj.is_kind_of(KindOf::Structure)
                && !obj.is_kind_of(KindOf::Infantry)
                && !obj.is_kind_of(KindOf::Vehicle)
                && !obj.is_kind_of(KindOf::Aircraft)
            {
                continue;
            }
            let dist = fire_pos.distance(obj.get_position());
            if dist <= range && best.map(|(_, d)| dist < d).unwrap_or(true) {
                best = Some((*id, dist));
            }
        }

        let Some((target_id, _)) = best else {
            return;
        };

        let mut destroyed = false;
        let mut kill_xp = 0.0;
        if let Some(target) = self.objects.get_mut(&target_id) {
            destroyed = target.take_damage(damage);
            if destroyed {
                kill_xp = target.thing.template.experience_value
                    * Self::veterancy_xp_multiplier(target.experience.level);
            }
        }

        if let Some(attacker) = self.objects.get_mut(&passenger_id) {
            if let Some(w) = attacker.weapon.as_mut() {
                w.last_fire_time = current_time;
            }
            if destroyed {
                attacker.gain_experience(kill_xp);
            }
        }

        if destroyed {
            self.mark_object_for_destruction(target_id, Some(team));
        }

        if is_battle_bus {
            self.battle_bus.record_passenger_fire();
        } else if is_combat_chinook {
            self.combat_chinook.record_passenger_fire();
        } else if is_listening_outpost {
            self.listening_outpost.record_passenger_fire();
        }
    }

    /// Residual fire-from-garrison: garrisoned infantry auto-engage nearest
    /// enemy in weapon range from the **container position**.
    /// Fail-closed: not C++ garrison weapon bone positions / multi-slot matrix.
    fn try_garrison_residual_fire(&mut self, garrisoned_id: ObjectId) {
        let current_time = self.frame as f32 * LOGIC_FRAME_TIMESTEP;

        let Some(attacker) = self.objects.get(&garrisoned_id) else {
            return;
        };
        if !attacker.is_alive() || attacker.weapon.is_none() {
            return;
        }
        let Some(weapon) = attacker.weapon.as_ref() else {
            return;
        };
        if !Object::weapon_ready(weapon, current_time) {
            return;
        }

        let container_id = attacker.container_id();
        let team = attacker.team;
        let range = weapon.range;
        let damage = weapon.damage;
        let fire_pos = container_id
            .and_then(|cid| self.objects.get(&cid).map(|c| c.get_position()))
            .unwrap_or_else(|| attacker.get_position());

        let mut best: Option<(ObjectId, f32)> = None;
        for (id, obj) in &self.objects {
            if *id == garrisoned_id || Some(*id) == container_id {
                continue;
            }
            if !obj.is_alive() || obj.team == team || obj.team == Team::Neutral {
                continue;
            }
            if !obj.is_kind_of(KindOf::Attackable)
                && !obj.is_kind_of(KindOf::Structure)
                && !obj.is_kind_of(KindOf::Infantry)
                && !obj.is_kind_of(KindOf::Vehicle)
                && !obj.is_kind_of(KindOf::Aircraft)
            {
                continue;
            }
            let dist = fire_pos.distance(obj.get_position());
            if dist <= range && best.map(|(_, d)| dist < d).unwrap_or(true) {
                best = Some((*id, dist));
            }
        }

        let Some((target_id, _)) = best else {
            return;
        };

        let mut destroyed = false;
        let mut kill_xp = 0.0;
        if let Some(target) = self.objects.get_mut(&target_id) {
            destroyed = target.take_damage(damage);
            if destroyed {
                kill_xp = target.thing.template.experience_value
                    * Self::veterancy_xp_multiplier(target.experience.level);
            }
        }

        if let Some(attacker) = self.objects.get_mut(&garrisoned_id) {
            if let Some(w) = attacker.weapon.as_mut() {
                w.last_fire_time = current_time;
            }
            if destroyed {
                attacker.gain_experience(kill_xp);
            }
        }

        if destroyed {
            self.mark_object_for_destruction(target_id, Some(team));
        }

        self.garrison_residual_fires = self.garrison_residual_fires.saturating_add(1);
    }

