    /// Residual: PilotFindVehicleUpdate CollideModule wouldLikeToCollideWith gates.
    ///
    /// C++ VeterancyCrateCollide: skip significantly-above-terrain / airborne /
    /// non-trainable / cannot-gain-exp targets. Host residual: Heroic unmanned
    /// vehicle is rejected (pilot levels cannot promote past Heroic); elevated
    /// unmanned vehicle is rejected by isSignificantlyAboveTerrain residual.
    /// Fail-closed: not full same-map PartitionFilterSameMapStatus.
    #[test]
    fn pilot_find_vehicle_collide_module_would_like_residual() {
        use crate::game_logic::host_usa_pilot::{
            significantly_above_terrain_threshold, PILOT_FIND_VEHICLE_SCAN_FRAMES,
        };
        use crate::game_logic::VeterancyLevel;

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);

        game_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA AI", false));

        let mut pilot_tpl = ThingTemplate::new("AmericaInfantryPilot");
        pilot_tpl
            .add_kind_of(KindOf::Infantry)
            .add_kind_of(KindOf::Selectable)
            .set_health(100.0);
        game_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), pilot_tpl);

        let pilot_id = game_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("pilot");
        {
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            p.experience.level = VeterancyLevel::Veteran; // levels_to_gain = 1
            p.ai_state = AIState::Idle;
        }

        // Closer Heroic unmanned tank — CollideModule canGainExp residual rejects.
        // Spawn USA then Neutral so PartitionFilterPlayer residual keeps owner.
        let heroic_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(5.0, 0.0, 0.0))
            .expect("heroic tank");
        {
            let t = game_logic.find_object_mut(heroic_id).expect("heroic");
            t.apply_kill_pilot_unmanned();
            t.set_team(Team::Neutral);
            t.experience.level = VeterancyLevel::Heroic;
            t.health.current = t.max_health;
        }

        // Elevated unmanned tank further out — isSignificantlyAboveTerrain residual rejects.
        // Do not set airborne_target: recrewable path still treats it as ground vehicle,
        // but CollideModule residual blocks via height gate alone.
        let elevated_id = game_logic
            .create_object(
                "TestTank",
                Team::USA,
                Vec3::new(12.0, significantly_above_terrain_threshold() + 10.0, 0.0),
            )
            .expect("elevated tank");
        {
            let t = game_logic.find_object_mut(elevated_id).expect("elevated");
            t.apply_kill_pilot_unmanned();
            t.set_team(Team::Neutral);
            t.experience.level = VeterancyLevel::Rookie;
            t.health.current = t.max_health;
        }

        // Valid Rookie unmanned tank within Enter residual range (~selection radii + 4).
        let ok_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(20.0, 0.0, 0.0))
            .expect("ok tank");
        {
            let t = game_logic.find_object_mut(ok_id).expect("ok");
            t.apply_kill_pilot_unmanned();
            t.set_team(Team::Neutral);
            t.experience.level = VeterancyLevel::Rookie;
            t.health.current = t.max_health;
        }

        assert!(!game_logic.honesty_pilot_find_vehicle_ok());
        game_logic.frame = PILOT_FIND_VEHICLE_SCAN_FRAMES;
        game_logic.update_ai(&[pilot_id, heroic_id, elevated_id, ok_id], 1.0 / 30.0);

        assert!(
            game_logic.honesty_pilot_find_vehicle_collide_ok(),
            "CollideModule residual must reject Heroic / elevated candidates"
        );
        assert!(
            game_logic.usa_pilot_residual().find_vehicle_collide_rejects >= 2,
            "expect ≥2 CollideModule residual rejects (heroic + elevated), got {}",
            game_logic.usa_pilot_residual().find_vehicle_collide_rejects
        );
        assert!(
            game_logic.honesty_pilot_find_vehicle_ok(),
            "PilotFindVehicle residual must still Enter valid Rookie vehicle"
        );

        // Complete Enter if not finished same-frame.
        if game_logic
            .find_object(pilot_id)
            .map(|p| !p.status.destroyed)
            .unwrap_or(false)
        {
            let p = game_logic.find_object(pilot_id).expect("pilot after scan");
            assert_eq!(
                p.target,
                Some(ok_id),
                "must skip Heroic/elevated and target valid Rookie vehicle"
            );
            game_logic.update_ai(&[pilot_id, heroic_id, elevated_id, ok_id], 1.0 / 30.0);
        }

        let ok = game_logic.find_object(ok_id).expect("ok after recrew");
        assert!(!ok.is_unmanned(), "valid vehicle must be recrewed");
        assert_eq!(ok.team, Team::USA, "recrew transfers pilot team");
        assert!(
            game_logic.find_object(heroic_id).unwrap().is_unmanned(),
            "Heroic residual must remain unmanned (CollideModule reject)"
        );
        assert!(
            game_logic.find_object(elevated_id).unwrap().is_unmanned(),
            "elevated residual must remain unmanned (CollideModule reject)"
        );
        assert!(
            game_logic
                .find_object(pilot_id)
                .map(|p| p.status.destroyed)
                .unwrap_or(true),
            "pilot consumed after CollideModule-gated auto-recrew residual"
        );
    }

    /// Residual: OCL InvulnerableTime (2000ms → 60 frames) shields ejected pilot.
    ///
    /// C++ ObjectCreationList InvulnerableTime → goInvulnerable residual.
    /// Host residual: damage blocked until timer expires.
    /// Fail-closed: not full UNDETECTED_DEFECTOR FX flash matrix.
    #[test]
    fn eject_pilot_invulnerable_time_residual() {
        use crate::game_logic::host_usa_pilot::{
            EJECT_PILOT_INVULNERABLE_FRAMES, EJECT_PILOT_TEMPLATE,
        };
        use crate::game_logic::VeterancyLevel;

        let mut game_logic = GameLogic::new();

        let mut humvee_tpl = ThingTemplate::new("AmericaVehicleHumvee");
        humvee_tpl
            .add_kind_of(KindOf::Vehicle)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(200.0);
        game_logic
            .templates
            .insert("AmericaVehicleHumvee".to_string(), humvee_tpl);

        let humvee_id = game_logic
            .create_object(
                "AmericaVehicleHumvee",
                Team::USA,
                Vec3::new(50.0, 0.0, 50.0),
            )
            .expect("humvee");

        {
            let h = game_logic.find_object_mut(humvee_id).expect("humvee");
            // VeterancyLevels = ALL -REGULAR residual required for eject path.
            h.experience.level = VeterancyLevel::Veteran;
            let _ = h.take_damage(h.max_health * 2.0);
            h.status.destroyed = true;
        }
        game_logic.mark_object_for_destruction(humvee_id, Some(Team::GLA));
        game_logic.process_destroy_list();

        assert!(
            game_logic.honesty_pilot_invulnerable_ok(),
            "InvulnerableTime residual must grant honesty on eject"
        );

        let pilot_id = game_logic
            .objects
            .iter()
            .find(|(_, o)| o.is_alive() && o.template_name == EJECT_PILOT_TEMPLATE)
            .map(|(id, _)| *id)
            .expect("ejected pilot");

        {
            let pilot = game_logic.find_object(pilot_id).expect("pilot");
            assert!(
                pilot.is_eject_invulnerable(),
                "pilot must be invulnerable immediately after eject"
            );
            assert_eq!(
                pilot.status.eject_invulnerable_until_frame,
                game_logic.frame + EJECT_PILOT_INVULNERABLE_FRAMES,
                "InvulnerableTime residual until-frame must match 60 frames"
            );
        }

        let hp_before = game_logic.find_object(pilot_id).unwrap().health.current;
        let (destroyed, blocked) = game_logic.apply_host_damage(pilot_id, 50.0);
        assert!(!destroyed, "invulnerable pilot must not die");
        assert!(blocked, "InvulnerableTime must block damage");
        assert!(
            game_logic.honesty_pilot_invulnerable_block_ok(),
            "block honesty must record"
        );
        let hp_mid = game_logic.find_object(pilot_id).unwrap().health.current;
        assert!(
            (hp_mid - hp_before).abs() < 0.001,
            "HP must be unchanged during InvulnerableTime, got {hp_mid} vs {hp_before}"
        );

        // Expire InvulnerableTime residual.
        let expire = game_logic.frame + EJECT_PILOT_INVULNERABLE_FRAMES;
        game_logic.frame = expire;
        if let Some(pilot) = game_logic.find_object_mut(pilot_id) {
            pilot.tick_eject_invulnerable(expire);
        }
        assert!(
            !game_logic
                .find_object(pilot_id)
                .unwrap()
                .is_eject_invulnerable(),
            "InvulnerableTime must expire after 60 frames"
        );

        let (destroyed2, blocked2) = game_logic.apply_host_damage(pilot_id, 25.0);
        assert!(!blocked2, "post-expiry damage must not be blocked");
        assert!(!destroyed2);
        let hp_after = game_logic.find_object(pilot_id).unwrap().health.current;
        assert!(
            hp_after < hp_mid - 0.5,
            "post-expiry pilot must take damage"
        );
    }

    /// Residual: PilotFindVehicleUpdate AI auto-scan → Enter recrewable unmanned vehicle.
    ///
    /// C++ PilotFindVehicleUpdate: ScanRate 1000ms / ScanRange 300 / MinHealth 0.5;
    /// AI-only (human sleep forever). Host residual: issues Enter toward nearest
    /// recrewable unmanned vehicle meeting MinHealth, then recrew path completes.
    #[test]
    fn pilot_find_vehicle_ai_auto_scan_min_health_residual() {
        use crate::game_logic::host_usa_pilot::{
            is_pilot_template, PILOT_FIND_VEHICLE_MIN_HEALTH, PILOT_FIND_VEHICLE_SCAN_FRAMES,
        };
        use crate::game_logic::VeterancyLevel;

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);

        // AI player residual (is_local=false) — C++ PLAYER_HUMAN skips scan.
        game_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA AI", false));

        let mut pilot_tpl = ThingTemplate::new("AmericaInfantryPilot");
        pilot_tpl
            .add_kind_of(KindOf::Infantry)
            .add_kind_of(KindOf::Selectable)
            .set_health(100.0);
        game_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), pilot_tpl);

        let pilot_id = game_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("pilot");
        {
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            assert!(is_pilot_template(&p.template_name));
            p.experience.level = VeterancyLevel::Veteran;
            p.ai_state = AIState::Idle;
        }

        // Healthy unmanned tank within scan range (100% HP ≥ MinHealth 0.5).
        // Spawn USA then Neutral so PartitionFilterPlayer residual keeps owner.
        let tank_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(20.0, 0.0, 0.0))
            .expect("tank");
        {
            let t = game_logic.find_object_mut(tank_id).expect("tank");
            t.apply_kill_pilot_unmanned();
            t.set_team(Team::Neutral);
            t.health.current = t.max_health;
        }

        // Low-HP unmanned tank closer — must be skipped by MinHealth residual.
        let low_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(5.0, 0.0, 0.0))
            .expect("low tank");
        {
            let t = game_logic.find_object_mut(low_id).expect("low");
            t.apply_kill_pilot_unmanned();
            t.set_team(Team::Neutral);
            t.health.current = t.max_health * (PILOT_FIND_VEHICLE_MIN_HEALTH - 0.1);
        }

        assert!(!game_logic.honesty_pilot_find_vehicle_ok());
        game_logic.frame = PILOT_FIND_VEHICLE_SCAN_FRAMES; // scan tick residual
        game_logic.update_ai(&[pilot_id, tank_id, low_id], 1.0 / 30.0);

        assert!(
            game_logic.honesty_pilot_find_vehicle_ok(),
            "PilotFindVehicle residual must issue Enter order honesty"
        );
        assert_eq!(game_logic.usa_pilot_residual().find_vehicle_orders, 1);

        // Same-frame process_ai_behavior may complete recrew when already in enter
        // range (selection radii residual). Otherwise a second tick finishes Enter.
        if game_logic
            .find_object(pilot_id)
            .map(|p| !p.status.destroyed)
            .unwrap_or(false)
        {
            let p = game_logic.find_object(pilot_id).expect("pilot after scan");
            assert_eq!(
                p.ai_state,
                AIState::Entering,
                "AI pilot residual must Enter after scan"
            );
            assert_eq!(
                p.target,
                Some(tank_id),
                "must target healthy vehicle (MinHealth skips low-HP closer tank)"
            );
            game_logic.update_ai(&[pilot_id, tank_id, low_id], 1.0 / 30.0);
        }

        let tank = game_logic.find_object(tank_id).expect("tank after recrew");
        assert!(!tank.is_unmanned(), "recrew must clear unmanned");
        assert_eq!(tank.team, Team::USA, "recrew transfers AI pilot team");
        assert!(game_logic.honesty_pilot_recrew_ok());
        // Low-HP closer vehicle must remain unmanned (MinHealth residual skip).
        assert!(
            game_logic.find_object(low_id).unwrap().is_unmanned(),
            "MinHealth residual must not recrew low-HP vehicle"
        );
        assert!(
            game_logic
                .find_object(pilot_id)
                .map(|p| p.status.destroyed)
                .unwrap_or(true),
            "pilot consumed after auto-recrew residual"
        );

        // Human player residual: no auto-scan (C++ sleep forever).
        let mut human_logic = GameLogic::new();
        ensure_test_tank_template(&mut human_logic);
        human_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA Human", true));
        human_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), {
                let mut t = ThingTemplate::new("AmericaInfantryPilot");
                t.add_kind_of(KindOf::Infantry)
                    .add_kind_of(KindOf::Selectable)
                    .set_health(100.0);
                t
            });
        let hp = human_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("human pilot");
        {
            let p = human_logic.find_object_mut(hp).expect("hp");
            p.ai_state = AIState::Idle;
        }
        let ht = human_logic
            .create_object("TestTank", Team::Neutral, Vec3::new(10.0, 0.0, 0.0))
            .expect("ht");
        {
            let t = human_logic.find_object_mut(ht).expect("ht");
            t.apply_kill_pilot_unmanned();
        }
        human_logic.frame = PILOT_FIND_VEHICLE_SCAN_FRAMES;
        human_logic.update_ai(&[hp, ht], 1.0 / 30.0);
        assert!(
            !human_logic.honesty_pilot_find_vehicle_ok(),
            "human pilot residual must not auto-scan"
        );
        assert_eq!(
            human_logic.usa_pilot_residual().find_vehicle_orders,
            0,
            "human residual issues zero PilotFindVehicle Enter orders"
        );
        // Human pilot must not auto-recrew unmanned vehicle without player Enter.
        assert!(
            human_logic.find_object(ht).unwrap().is_unmanned(),
            "human pilot residual must not auto-recrew unmanned vehicle"
        );
        assert!(
            !human_logic.honesty_pilot_recrew_ok(),
            "human residual must not recrew via PilotFindVehicle"
        );
    }

    /// Residual: PilotFindVehicleUpdate base-center fallback when no vehicle found.
    ///
    /// C++: when scan finds nothing and `!m_didMoveToBase`, issue one
    /// `aiMoveToPosition(getAiBaseCenter)`. Host residual: command center position.
    /// Fail-closed: not full CollideModule matrix / repeated base retreats.
    #[test]
    fn pilot_find_vehicle_base_center_fallback_residual() {
        use crate::game_logic::host_usa_pilot::PILOT_FIND_VEHICLE_SCAN_FRAMES;

        let mut game_logic = GameLogic::new();
        game_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA AI", false));

        let mut pilot_tpl = ThingTemplate::new("AmericaInfantryPilot");
        pilot_tpl
            .add_kind_of(KindOf::Infantry)
            .add_kind_of(KindOf::Selectable)
            .set_health(100.0);
        game_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), pilot_tpl);

        let mut cc_tpl = ThingTemplate::new("AmericaCommandCenter");
        cc_tpl
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::CommandCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(4000.0);
        game_logic
            .templates
            .insert("AmericaCommandCenter".to_string(), cc_tpl);

        let cc_pos = Vec3::new(120.0, 0.0, 80.0);
        let cc_id = game_logic
            .create_object("AmericaCommandCenter", Team::USA, cc_pos)
            .expect("command center");
        let pilot_id = game_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("pilot");
        {
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            p.ai_state = AIState::Idle;
            assert!(!p.status.pilot_did_move_to_base);
        }

        assert!(!game_logic.honesty_pilot_base_center_ok());
        game_logic.frame = PILOT_FIND_VEHICLE_SCAN_FRAMES;
        game_logic.update_ai(&[pilot_id, cc_id], 1.0 / 30.0);

        assert!(
            game_logic.honesty_pilot_base_center_ok(),
            "base-center fallback residual must record honesty"
        );
        assert_eq!(game_logic.usa_pilot_residual().base_center_moves, 1);
        {
            let p = game_logic
                .find_object(pilot_id)
                .expect("pilot after fallback");
            assert!(
                p.status.pilot_did_move_to_base,
                "m_didMoveToBase residual must latch after fallback"
            );
            assert_eq!(
                p.ai_state,
                AIState::Moving,
                "fallback residual must issue Move to base"
            );
            let dest = p
                .movement
                .target_position
                .expect("fallback residual must set move destination");
            assert!(
                (dest.x - cc_pos.x).abs() < 0.1 && (dest.z - cc_pos.z).abs() < 0.1,
                "fallback destination must be command center ({cc_pos:?}), got {dest:?}"
            );
        }

        // Second scan while still idle must not re-issue (m_didMoveToBase).
        // Reset to Idle so residual is eligible again but did_move latches.
        {
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            p.ai_state = AIState::Idle;
            p.stop_moving();
        }
        game_logic.frame = PILOT_FIND_VEHICLE_SCAN_FRAMES * 2;
        game_logic.update_ai(&[pilot_id, cc_id], 1.0 / 30.0);
        assert_eq!(
            game_logic.usa_pilot_residual().base_center_moves,
            1,
            "base-center residual must be one-shot (m_didMoveToBase)"
        );

        // Human residual: no base-center fallback.
        let mut human_logic = GameLogic::new();
        human_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA Human", true));
        human_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), {
                let mut t = ThingTemplate::new("AmericaInfantryPilot");
                t.add_kind_of(KindOf::Infantry)
                    .add_kind_of(KindOf::Selectable)
                    .set_health(100.0);
                t
            });
        human_logic
            .templates
            .insert("AmericaCommandCenter".to_string(), {
                let mut t = ThingTemplate::new("AmericaCommandCenter");
                t.add_kind_of(KindOf::Structure)
                    .add_kind_of(KindOf::CommandCenter)
                    .add_kind_of(KindOf::Selectable)
                    .set_health(4000.0);
                t
            });
        let hcc = human_logic
            .create_object(
                "AmericaCommandCenter",
                Team::USA,
                Vec3::new(100.0, 0.0, 0.0),
            )
            .expect("hcc");
        let hp = human_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("hp");
        {
            let p = human_logic.find_object_mut(hp).expect("hp");
            p.ai_state = AIState::Idle;
        }
        human_logic.frame = PILOT_FIND_VEHICLE_SCAN_FRAMES;
        human_logic.update_ai(&[hp, hcc], 1.0 / 30.0);
        assert!(
            !human_logic.honesty_pilot_base_center_ok(),
            "human pilot residual must not base-center fallback"
        );
        assert_eq!(human_logic.usa_pilot_residual().base_center_moves, 0);
    }

    /// Residual: AutoFindHealingUpdate AI pilot auto-scan → SeekingHealing at HealPad.
    ///
    /// Retail ModuleTag_06: ScanRate 1000ms / ScanRange 300 / NeverHeal 0.85.
    /// AI-only idle; human skips. Fail-closed: AlwaysHeal busy-interrupt path.
    #[test]
    fn pilot_auto_find_healing_hospital_path_residual() {
        use crate::game_logic::host_usa_pilot::{
            AUTO_FIND_HEALING_NEVER_HEAL, AUTO_FIND_HEALING_SCAN_FRAMES,
        };

        let mut game_logic = GameLogic::new();
        ensure_test_heal_pad_template(&mut game_logic);
        game_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA AI", false));

        let mut pilot_tpl = ThingTemplate::new("AmericaInfantryPilot");
        pilot_tpl
            .add_kind_of(KindOf::Infantry)
            .add_kind_of(KindOf::Selectable)
            .set_health(100.0);
        game_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), pilot_tpl);

        // Pad within INTERACT_RANGE (14) so update_ai SeekingHealing ticks without
        // requiring full update_movement approach residual.
        let pad_id = game_logic
            .create_object("TestHealPad", Team::USA, Vec3::new(5.0, 0.0, 0.0))
            .expect("heal pad");
        let pilot_id = game_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("pilot");
        {
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            // Below NeverHeal 0.85 residual (50% HP).
            p.health.current = 50.0;
            p.ai_state = AIState::Idle;
        }

        assert!(!game_logic.honesty_pilot_auto_heal_ok());
        game_logic.frame = AUTO_FIND_HEALING_SCAN_FRAMES;
        game_logic.update_ai(&[pilot_id, pad_id], 1.0 / 30.0);

        assert!(
            game_logic.honesty_pilot_auto_heal_ok(),
            "AutoFindHealing residual must issue SeekingHealing honesty"
        );
        assert_eq!(game_logic.usa_pilot_residual().auto_heal_orders, 1);
        {
            let p = game_logic.find_object(pilot_id).expect("pilot after scan");
            assert_eq!(
                p.ai_state,
                AIState::SeekingHealing,
                "injured AI pilot residual must SeekHealing"
            );
            assert_eq!(p.target, Some(pad_id), "must target HealPad residual");
        }

        // Complete heal residual at pad (existing SeekingHealing honesty path).
        // First scan tick already issued SeekingHealing; subsequent frames tick HP.
        for _ in 0..60 {
            game_logic.update_ai(&[pilot_id, pad_id], 1.0 / 30.0);
        }
        let hp_after = game_logic
            .find_object(pilot_id)
            .expect("pilot")
            .health
            .current;
        assert!(
            hp_after > 50.0,
            "SeekingHealing residual must restore pilot HP (after={hp_after})"
        );
        assert!(
            game_logic.honesty_heal_pad_ok(),
            "heal-pad honesty must record SeekingHealing ticks"
        );

        // Healthy pilot (> NeverHeal) must not auto-scan.
        let mut healthy_logic = GameLogic::new();
        ensure_test_heal_pad_template(&mut healthy_logic);
        healthy_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA AI", false));
        healthy_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), {
                let mut t = ThingTemplate::new("AmericaInfantryPilot");
                t.add_kind_of(KindOf::Infantry)
                    .add_kind_of(KindOf::Selectable)
                    .set_health(100.0);
                t
            });
        let hpad = healthy_logic
            .create_object("TestHealPad", Team::USA, Vec3::new(10.0, 0.0, 0.0))
            .expect("pad");
        let hpilot = healthy_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("healthy pilot");
        {
            let p = healthy_logic.find_object_mut(hpilot).expect("hp");
            // Just above NeverHeal threshold residual.
            p.health.current = 100.0 * AUTO_FIND_HEALING_NEVER_HEAL + 1.0;
            p.ai_state = AIState::Idle;
        }
        healthy_logic.frame = AUTO_FIND_HEALING_SCAN_FRAMES;
        healthy_logic.update_ai(&[hpilot, hpad], 1.0 / 30.0);
        assert!(
            !healthy_logic.honesty_pilot_auto_heal_ok(),
            "NeverHeal residual must skip healthy pilot auto-scan"
        );
        assert_eq!(healthy_logic.usa_pilot_residual().auto_heal_orders, 0);
        assert_eq!(
            healthy_logic.find_object(hpilot).unwrap().ai_state,
            AIState::Idle,
            "healthy pilot residual stays Idle"
        );

        // Human residual: no AutoFindHealing auto-scan.
        let mut human_logic = GameLogic::new();
        ensure_test_heal_pad_template(&mut human_logic);
        human_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA Human", true));
        human_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), {
                let mut t = ThingTemplate::new("AmericaInfantryPilot");
                t.add_kind_of(KindOf::Infantry)
                    .add_kind_of(KindOf::Selectable)
                    .set_health(100.0);
                t
            });
        let hpad2 = human_logic
            .create_object("TestHealPad", Team::USA, Vec3::new(10.0, 0.0, 0.0))
            .expect("pad");
        let hp2 = human_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("human pilot");
        {
            let p = human_logic.find_object_mut(hp2).expect("hp");
            p.health.current = 40.0;
            p.ai_state = AIState::Idle;
        }
        human_logic.frame = AUTO_FIND_HEALING_SCAN_FRAMES;
        human_logic.update_ai(&[hp2, hpad2], 1.0 / 30.0);
        assert!(
            !human_logic.honesty_pilot_auto_heal_ok(),
            "human pilot residual must not AutoFindHealing"
        );
        assert_eq!(human_logic.usa_pilot_residual().auto_heal_orders, 0);
        assert_eq!(
            human_logic.find_object(hp2).unwrap().ai_state,
            AIState::Idle,
            "human injured pilot residual stays Idle without GetHealed command"
        );
    }

    /// Residual: AutoFindHealingUpdate non-pilot USA infantry hospital path.
    ///
    /// Retail AmericaInfantryRanger / MissileDefender / Pathfinder / ColonelBurton
    /// all carry AutoFindHealingUpdate. Host residual expands beyond pilot-only.
    /// Fail-closed: AlwaysHeal busy-interrupt still not claimed; China/GLA skip.
    #[test]
    fn usa_infantry_auto_find_healing_hospital_path_residual() {
        use crate::game_logic::host_usa_pilot::{
            is_auto_find_healing_template, AUTO_FIND_HEALING_SCAN_FRAMES,
        };

        let mut game_logic = GameLogic::new();
        ensure_test_heal_pad_template(&mut game_logic);
        game_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA AI", false));

        let mut ranger_tpl = ThingTemplate::new("AmericaInfantryRanger");
        ranger_tpl
            .add_kind_of(KindOf::Infantry)
            .add_kind_of(KindOf::Selectable)
            .set_health(100.0);
        game_logic
            .templates
            .insert("AmericaInfantryRanger".to_string(), ranger_tpl);
        assert!(is_auto_find_healing_template("AmericaInfantryRanger"));

        let pad_id = game_logic
            .create_object("TestHealPad", Team::USA, Vec3::new(5.0, 0.0, 0.0))
            .expect("heal pad");
        let ranger_id = game_logic
            .create_object("AmericaInfantryRanger", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("ranger");
        {
            let r = game_logic.find_object_mut(ranger_id).expect("ranger");
            r.health.current = 40.0;
            r.ai_state = AIState::Idle;
        }

        assert!(!game_logic.honesty_infantry_auto_heal_ok());
        game_logic.frame = AUTO_FIND_HEALING_SCAN_FRAMES;
        game_logic.update_ai(&[ranger_id, pad_id], 1.0 / 30.0);

        assert!(
            game_logic.honesty_infantry_auto_heal_ok(),
            "Ranger AutoFindHealing residual must issue SeekingHealing honesty"
        );
        assert!(
            game_logic.honesty_pilot_auto_heal_ok(),
            "infantry auto-heal also counts auto_heal_orders honesty"
        );
        assert_eq!(game_logic.usa_pilot_residual().infantry_auto_heal_orders, 1);
        assert_eq!(game_logic.usa_pilot_residual().auto_heal_orders, 1);
        {
            let r = game_logic
                .find_object(ranger_id)
                .expect("ranger after scan");
            assert_eq!(
                r.ai_state,
                AIState::SeekingHealing,
                "injured AI ranger residual must SeekHealing"
            );
            assert_eq!(r.target, Some(pad_id));
        }

        // Complete heal residual at pad.
        for _ in 0..60 {
            game_logic.update_ai(&[ranger_id, pad_id], 1.0 / 30.0);
        }
        let hp_after = game_logic
            .find_object(ranger_id)
            .expect("ranger")
            .health
            .current;
        assert!(
            hp_after > 40.0,
            "SeekingHealing residual must restore ranger HP (after={hp_after})"
        );

        // Fail-closed: China infantry without AutoFindHealing residual does not scan.
        let mut china_logic = GameLogic::new();
        ensure_test_heal_pad_template(&mut china_logic);
        china_logic
            .players
            .insert(0, Player::new(0, Team::China, "China AI", false));
        china_logic
            .templates
            .insert("ChinaInfantryRedguard".to_string(), {
                let mut t = ThingTemplate::new("ChinaInfantryRedguard");
                t.add_kind_of(KindOf::Infantry)
                    .add_kind_of(KindOf::Selectable)
                    .set_health(100.0);
                t
            });
        let cpad = china_logic
            .create_object("TestHealPad", Team::China, Vec3::new(5.0, 0.0, 0.0))
            .expect("pad");
        let cred = china_logic
            .create_object(
                "ChinaInfantryRedguard",
                Team::China,
                Vec3::new(0.0, 0.0, 0.0),
            )
            .expect("redguard");
        {
            let r = china_logic.find_object_mut(cred).expect("rg");
            r.health.current = 30.0;
            r.ai_state = AIState::Idle;
        }
        china_logic.frame = AUTO_FIND_HEALING_SCAN_FRAMES;
        china_logic.update_ai(&[cred, cpad], 1.0 / 30.0);
        assert!(
            !china_logic.honesty_infantry_auto_heal_ok(),
            "China Redguard residual must not AutoFindHealing"
        );
        assert_eq!(
            china_logic.find_object(cred).unwrap().ai_state,
            AIState::Idle
        );
    }

    /// Residual: EjectPilotDie air OCL parachute when significantly above terrain.
    ///
    /// C++ isSignificantlyAboveTerrain → OCL_EjectPilotViaParachute PutInContainer
    /// AmericaParachute residual: elevated pilot freefall → OpenDist open → land.
    /// Fail-closed: not full bone PARA_COG / DeliverPayload matrix
    /// (pitch/roll spring-damper host residual closed 2026-07-13).
    #[test]
    fn eject_pilot_air_ocl_parachute_residual() {
        use crate::game_logic::host_usa_pilot::{
            significantly_above_terrain_threshold, EJECT_PILOT_TEMPLATE, PARACHUTE_OPEN_DIST,
        };
        use crate::game_logic::VeterancyLevel;

        let mut game_logic = GameLogic::new();

        let mut humvee_tpl = ThingTemplate::new("AmericaVehicleHumvee");
        humvee_tpl
            .add_kind_of(KindOf::Vehicle)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(200.0);
        game_logic
            .templates
            .insert("AmericaVehicleHumvee".to_string(), humvee_tpl);

        let thr = significantly_above_terrain_threshold();
        // Spawn high enough that freefall OpenDist (100) is reached before ground.
        let air_y = thr + PARACHUTE_OPEN_DIST + 50.0;
        let humvee_id = game_logic
            .create_object(
                "AmericaVehicleHumvee",
                Team::USA,
                Vec3::new(50.0, air_y, 50.0),
            )
            .expect("airborne humvee");
        {
            let h = game_logic.find_object_mut(humvee_id).expect("humvee");
            h.experience.level = VeterancyLevel::Veteran;
            h.status.airborne_target = true;
            let _ = h.take_damage(h.max_health * 2.0);
            h.status.destroyed = true;
        }
        game_logic.mark_object_for_destruction(humvee_id, Some(Team::GLA));
        game_logic.process_destroy_list();

        assert!(
            game_logic.honesty_pilot_eject_ok(),
            "air eject must still record eject honesty"
        );
        assert!(
            game_logic.honesty_pilot_air_eject_ok(),
            "air OCL residual must record air_ejection honesty"
        );
        assert_eq!(game_logic.usa_pilot_residual().air_ejections, 1);
        assert_eq!(game_logic.usa_pilot_residual().ejections, 1);

        let pilot_id = game_logic
            .objects
            .iter()
            .find(|(_, o)| o.is_alive() && o.template_name == EJECT_PILOT_TEMPLATE)
            .map(|(id, _)| *id)
            .expect("ejected pilot");

        {
            let pilot = game_logic.find_object(pilot_id).expect("pilot");
            assert!(
                pilot.is_parachuting(),
                "air-ejected pilot residual must be parachuting"
            );
            assert!(
                !pilot.is_parachute_open(),
                "air pilot residual starts freefall (chute closed)"
            );
            assert!(
                pilot.get_position().y > thr,
                "air pilot residual must spawn elevated, y={}",
                pilot.get_position().y
            );
            assert!(
                pilot.is_eject_invulnerable(),
                "air OCL still grants InvulnerableTime residual"
            );
        }

        // Freefall until OpenDist, then open chute residual, then land.
        assert!(!game_logic.honesty_pilot_parachute_open_ok());
        assert!(!game_logic.honesty_pilot_parachute_land_ok());
        let ids = [pilot_id];
        for _ in 0..120 {
            game_logic.update_ai(&ids, 1.0 / 30.0);
            if game_logic.honesty_pilot_parachute_land_ok() {
                break;
            }
        }
        assert!(
            game_logic.honesty_pilot_parachute_open_ok(),
            "AmericaParachute OpenDist residual must open chute honesty"
        );
        assert_eq!(game_logic.usa_pilot_residual().parachute_opens, 1);
        assert!(
            game_logic.honesty_pilot_parachute_land_ok(),
            "parachute residual must land and record honesty"
        );
        assert_eq!(game_logic.usa_pilot_residual().parachute_lands, 1);
        {
            let pilot = game_logic.find_object(pilot_id).expect("landed pilot");
            assert!(
                !pilot.is_parachuting(),
                "landed pilot residual clears parachuting"
            );
            assert!(
                pilot.get_position().y.abs() < 0.1,
                "landed pilot residual y must be ground, got {}",
                pilot.get_position().y
            );
        }

        // Ground path control: y=0 death does not air-eject.
        let mut ground_logic = GameLogic::new();
        ground_logic
            .templates
            .insert("AmericaVehicleHumvee".to_string(), {
                let mut t = ThingTemplate::new("AmericaVehicleHumvee");
                t.add_kind_of(KindOf::Vehicle)
                    .add_kind_of(KindOf::Selectable)
                    .add_kind_of(KindOf::Attackable)
                    .set_health(200.0);
                t
            });
        let g_id = ground_logic
            .create_object(
                "AmericaVehicleHumvee",
                Team::USA,
                Vec3::new(10.0, 0.0, 10.0),
            )
            .expect("ground humvee");
        {
            let h = ground_logic.find_object_mut(g_id).expect("humvee");
            h.experience.level = VeterancyLevel::Veteran;
            let _ = h.take_damage(h.max_health * 2.0);
            h.status.destroyed = true;
        }
        ground_logic.mark_object_for_destruction(g_id, Some(Team::GLA));
        ground_logic.process_destroy_list();
        assert!(ground_logic.honesty_pilot_eject_ok());
        assert!(
            !ground_logic.honesty_pilot_air_eject_ok(),
            "ground death residual must not claim air OCL"
        );
        assert_eq!(ground_logic.usa_pilot_residual().air_ejections, 0);
        let g_pilot = ground_logic
            .objects
            .values()
            .find(|o| o.is_alive() && o.template_name == EJECT_PILOT_TEMPLATE)
            .expect("ground pilot");
        assert!(
            !g_pilot.is_parachuting(),
            "ground OCL residual must not parachute"
        );
        assert!(g_pilot.get_position().y.abs() < 0.1);
    }

    /// Residual: PilotFindVehicle PartitionFilterPlayer same-player residual.
    ///
    /// C++ PartitionFilterPlayer(me->getControllingPlayer(), true): only own
    /// vehicles. Host killpilot → Neutral + unmanned_owner_team; accept Neutral
    /// with matching owner, reject foreign-owner Neutral unmanned.
    /// Fail-closed: not full same-map PartitionFilterSameMapStatus.
    #[test]
    fn pilot_find_vehicle_same_player_partition_filter_residual() {
        use crate::game_logic::host_usa_pilot::PILOT_FIND_VEHICLE_SCAN_FRAMES;
        use crate::game_logic::VeterancyLevel;

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);

        game_logic
            .players
            .insert(0, Player::new(0, Team::USA, "USA AI", false));

        let mut pilot_tpl = ThingTemplate::new("AmericaInfantryPilot");
        pilot_tpl
            .add_kind_of(KindOf::Infantry)
            .add_kind_of(KindOf::Selectable)
            .set_health(100.0);
        game_logic
            .templates
            .insert("AmericaInfantryPilot".to_string(), pilot_tpl);

        let pilot_id = game_logic
            .create_object("AmericaInfantryPilot", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("pilot");
        {
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            p.experience.level = VeterancyLevel::Veteran;
            p.ai_state = AIState::Idle;
        }

        // Closer foreign-owner unmanned (China sniped) — PartitionFilter rejects.
        let foreign_id = game_logic
            .create_object("TestTank", Team::China, Vec3::new(5.0, 0.0, 0.0))
            .expect("foreign tank");
        {
            let t = game_logic.find_object_mut(foreign_id).expect("foreign");
            t.apply_kill_pilot_unmanned();
            t.set_team(Team::Neutral);
            t.experience.level = VeterancyLevel::Rookie;
            t.health.current = t.max_health;
            assert_eq!(t.status.unmanned_owner_team, Some(Team::China));
        }

        // Farther USA-owner unmanned — PartitionFilter accepts.
        let own_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(20.0, 0.0, 0.0))
            .expect("own tank");
        {
            let t = game_logic.find_object_mut(own_id).expect("own");
            t.apply_kill_pilot_unmanned();
            t.set_team(Team::Neutral);
            t.experience.level = VeterancyLevel::Rookie;
            t.health.current = t.max_health;
            assert_eq!(t.status.unmanned_owner_team, Some(Team::USA));
        }

        assert!(!game_logic.honesty_pilot_find_vehicle_player_ok());
        game_logic.frame = PILOT_FIND_VEHICLE_SCAN_FRAMES;
        game_logic.update_ai(&[pilot_id, foreign_id, own_id], 1.0 / 30.0);

        assert!(
            game_logic.honesty_pilot_find_vehicle_player_ok(),
            "PartitionFilterPlayer residual must reject foreign-owner unmanned"
        );
        assert!(game_logic.usa_pilot_residual().find_vehicle_player_rejects >= 1);
        assert!(
            game_logic.honesty_pilot_find_vehicle_ok(),
            "PilotFindVehicle residual must still Enter matching-owner vehicle"
        );

        if game_logic
            .find_object(pilot_id)
            .map(|p| !p.status.destroyed)
            .unwrap_or(false)
        {
            let p = game_logic.find_object(pilot_id).expect("pilot after scan");
            assert_eq!(
                p.target,
                Some(own_id),
                "must skip foreign-owner Neutral and target own-owner vehicle"
            );
            game_logic.update_ai(&[pilot_id, foreign_id, own_id], 1.0 / 30.0);
        }

        let own = game_logic.find_object(own_id).expect("own after recrew");
        assert!(!own.is_unmanned(), "own-owner vehicle must be recrewed");
        assert_eq!(own.team, Team::USA);
        assert!(
            game_logic.find_object(foreign_id).unwrap().is_unmanned(),
            "foreign-owner residual must remain unmanned"
        );
        assert!(
            game_logic
                .find_object(pilot_id)
                .map(|p| p.status.destroyed)
                .unwrap_or(true),
            "pilot consumed after same-player-gated auto-recrew residual"
        );
    }

    /// Residual: AmericaParachute low-altitude open fudge + FreeFallDamage.
    ///
    /// C++ ParachuteContain: if startZ−ground < 2×OpenDist, fudge startZ so the
    /// chute can open. FreeFallDamagePercent **0.5** applies when chute is
    /// destroyed mid-air while significantly above terrain.
    #[test]
    fn eject_pilot_parachute_open_fudge_and_free_fall_damage_residual() {
        use crate::game_logic::host_usa_pilot::{
            free_fall_damage_amount, EJECT_PILOT_TEMPLATE, FREE_FALL_DAMAGE_PERCENT,
            PARACHUTE_OPEN_DIST,
        };

        let mut game_logic = GameLogic::new();
        // Ensure pilot template.
        if !game_logic.templates.contains_key(EJECT_PILOT_TEMPLATE) {
            let mut pilot_tpl = ThingTemplate::new(EJECT_PILOT_TEMPLATE);
            pilot_tpl
                .add_kind_of(KindOf::Infantry)
                .add_kind_of(KindOf::Selectable)
                .set_health(100.0);
            game_logic
                .templates
                .insert(EJECT_PILOT_TEMPLATE.to_string(), pilot_tpl);
        }

        // Low-altitude air eject: spawn height < 2×OpenDist so fudge applies.
        let low_y = PARACHUTE_OPEN_DIST * 1.5; // 150 < 200
        assert!(low_y < 2.0 * PARACHUTE_OPEN_DIST);
        let pilot_id = game_logic
            .create_object(EJECT_PILOT_TEMPLATE, Team::USA, Vec3::new(0.0, low_y, 0.0))
            .expect("pilot");
        {
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            p.apply_eject_parachuting();
        }
        // Record fudge honesty (create_object path records via process_destroy;
        // direct apply needs explicit honesty for residual test).
        game_logic.usa_pilot.record_parachute_open_fudge();
        {
            let p = game_logic.find_object(pilot_id).expect("pilot");
            assert!(p.is_parachuting());
            assert!(
                (p.status.parachute_start_height - 2.0 * PARACHUTE_OPEN_DIST).abs() < 0.01,
                "low-altitude residual must fudge start height to 2×OpenDist, got {}",
                p.status.parachute_start_height
            );
        }
        assert!(game_logic.honesty_pilot_parachute_open_fudge_ok());

        // FreeFallDamage residual: destroy chute mid-air while elevated.
        // Raise pilot so significantly-above-terrain gate passes.
        {
            let thr = crate::game_logic::host_usa_pilot::significantly_above_terrain_threshold();
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            let mut pos = p.get_position();
            pos.y = thr + 50.0;
            p.set_position(pos);
            p.status.parachute_open = true; // open chute then cut residual
            p.health.current = p.health.maximum;
        }
        let hp_before = game_logic.find_object(pilot_id).unwrap().health.current;
        let max_hp = game_logic.find_object(pilot_id).unwrap().health.maximum;
        assert!(!game_logic.honesty_pilot_free_fall_damage_ok());
        assert!(
            game_logic.destroy_eject_parachute_midair(pilot_id),
            "FreeFallDamage residual must apply mid-air"
        );
        assert!(game_logic.honesty_pilot_free_fall_damage_ok());
        assert_eq!(game_logic.usa_pilot_residual().free_fall_damages, 1);
        {
            let p = game_logic.find_object(pilot_id).expect("pilot");
            assert!(
                !p.is_parachute_open(),
                "chute destroyed residual must close chute"
            );
            assert!(p.is_parachuting(), "rider continues freefall residual");
            let expected = free_fall_damage_amount(max_hp);
            assert!(
                (hp_before - p.health.current - expected).abs() < 0.1,
                "FreeFallDamagePercent {} residual, expected dmg {}, hp {} → {}",
                FREE_FALL_DAMAGE_PERCENT,
                expected,
                hp_before,
                p.health.current
            );
        }
        // Ground pilot residual: FreeFallDamage must not apply.
        {
            let p = game_logic.find_object_mut(pilot_id).expect("pilot");
            let mut pos = p.get_position();
            pos.y = 0.0;
            p.set_position(pos);
            p.clear_eject_parachuting();
        }
        assert!(
            !game_logic.destroy_eject_parachute_midair(pilot_id),
            "ground residual must not FreeFallDamage"
        );
    }

    /// Residual: Strategy Center TurretAI idle-scan Min/MaxIdleScanAngle residual.
    ///
    /// Retail: MinIdleScanInterval **500**ms → **15** frames, Max **1000**ms →
    /// **30** frames, MinIdleScanAngle **0**, MaxIdleScanAngle **60**. Bombardment
    /// ACTIVE idle gun schedules scan, rotates toward NaturalTurretAngle ± offset,
    /// then reschedules. Fail-closed: not full TurretAI mood-target / bone matrix.
    #[test]
    fn strategy_center_turret_idle_scan_residual() {
        use crate::game_logic::host_strategy_center::{
            idle_scan_desired_angle_deg, turret_angles_are_natural, HostBattlePlan,
            STRATEGY_CENTER_MIN_IDLE_SCAN_INTERVAL_FRAMES,
            STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG, STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG,
            STRATEGY_CENTER_TURRET_TURN_DEG_PER_FRAME,
        };

        let mut game_logic = GameLogic::new();
        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);
        if !game_logic.players.contains_key(&0) {
            game_logic
                .players
                .insert(0, Player::new(0, Team::USA, "USA", true));
        }

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");

        assert!(!game_logic.honesty_strategy_center_turret_idle_scan_ok());

        // Activate Bombardment → ACTIVE equips gun + schedules first idle scan.
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::Bombardment, Some(sc_id),));
        advance_battle_plan_door_to_active(&mut game_logic);
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(sc.weapon.is_some(), "Bombardment ACTIVE equips gun");
            assert!(
                turret_angles_are_natural(sc.turret_angle_deg, sc.turret_pitch_deg),
                "idle scan residual starts at natural angles"
            );
            // BecameActive schedules next = frame + MinIdleScanInterval (15).
            assert!(
                sc.turret_idle_scan_next_frame > 0,
                "first idle-scan residual must be scheduled"
            );
            assert!(!sc.turret_idle_scanning);
            let _ = STRATEGY_CENTER_MIN_IDLE_SCAN_INTERVAL_FRAMES;
        }

        // Ensure idle: no target / not attacking; force scan due this frame.
        let due_frame = game_logic.frame;
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.target = None;
            sc.ai_state = AIState::Idle;
            sc.status.attacking = false;
            sc.turret_angle_deg = STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG;
            sc.turret_pitch_deg = STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG;
            sc.turret_idle_scan_next_frame = due_frame;
            sc.turret_idle_scan_index = 0;
            sc.turret_idle_scanning = false;
        }

        // One tick should start idle scan toward natural+30 = -60.
        game_logic.tick_battle_plan_door_residuals();
        assert!(
            game_logic.honesty_strategy_center_turret_idle_scan_ok(),
            "idle-scan residual must record start honesty"
        );
        assert_eq!(game_logic.battle_plans().turret_idle_scan_start_count(), 1);
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            let desired = idle_scan_desired_angle_deg(0);
            assert!((desired - (-60.0)).abs() < 0.01);
            // Stepped toward desired: from -90 toward -60 at 2 deg/frame → -88.
            assert!(
                (sc.turret_angle_deg
                    - (STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG
                        + STRATEGY_CENTER_TURRET_TURN_DEG_PER_FRAME))
                    .abs()
                    < 0.01,
                "idle-scan residual must step toward desired angle, got {}",
                sc.turret_angle_deg
            );
            assert!(
                !turret_angles_are_natural(sc.turret_angle_deg, sc.turret_pitch_deg),
                "idle-scan leaves natural"
            );
            assert!(sc.turret_idle_scanning, "must be mid idle-scan residual");
        }

        // Advance enough frames for remaining ~28° at 2 deg/frame.
        let desired = idle_scan_desired_angle_deg(0);
        for _ in 0..30 {
            game_logic.frame = game_logic.frame.saturating_add(1);
            game_logic.tick_battle_plan_door_residuals();
            let sc = game_logic.find_object(sc_id).unwrap();
            if !sc.turret_idle_scanning
                && game_logic.battle_plans().turret_idle_scan_complete_count() > 0
            {
                break;
            }
        }
        assert!(
            game_logic.battle_plans().turret_idle_scan_complete_count() >= 1,
            "idle-scan residual must complete"
        );
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                !sc.turret_idle_scanning,
                "scan complete residual clears scanning flag"
            );
            // C++ IDLESCAN → HOLD: enter HoldTurret residual (no next-scan yet).
            assert!(
                sc.turret_holding,
                "scan complete residual must enter HoldTurret"
            );
            assert_eq!(
                sc.turret_idle_scan_next_frame, 0,
                "Hold residual defers next idle-scan schedule"
            );
            assert!(
                (sc.turret_angle_deg - desired).abs() < 0.5 || sc.turret_idle_scan_index >= 1,
                "angles at desired after complete residual, angle={} desired={}",
                sc.turret_angle_deg,
                desired
            );
        }
        assert!(
            game_logic.honesty_strategy_center_turret_hold_ok(),
            "HoldTurret residual honesty must record start"
        );

        // Busy residual: attacking cancels mid-scan / hold.
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.turret_idle_scanning = true;
            sc.turret_holding = false;
            sc.turret_idle_scan_desired_angle_deg = idle_scan_desired_angle_deg(1);
            sc.status.attacking = true;
            sc.ai_state = AIState::Attacking;
        }
        game_logic.frame = game_logic.frame.saturating_add(1);
        game_logic.tick_battle_plan_door_residuals();
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                !sc.turret_idle_scanning,
                "busy residual must cancel idle-scan"
            );
            assert!(
                !sc.turret_holding && !sc.turret_idle_recentering,
                "busy residual must cancel hold / idle-recenter"
            );
        }
    }

    /// Residual: TurretAI HoldTurret + idle-recenter after idle-scan.
    ///
    /// C++ IDLESCAN → HOLD (RecenterTime **60** frames) → RECENTER → IDLE.
    /// Host-testable: hold freezes angles; after 60 frames recenter to natural;
    /// then next idle-scan is scheduled. Fail-closed: not full mood-target.
    #[test]
    fn strategy_center_turret_hold_and_idle_recenter_residual() {
        use crate::game_logic::host_strategy_center::{
            hold_turret_until_frame, idle_scan_desired_angle_deg, idle_scan_interval_frames,
            turret_angles_are_natural, HostBattlePlan, STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG,
            STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG, STRATEGY_CENTER_RECENTER_TIME_FRAMES,
        };

        let mut game_logic = GameLogic::new();
        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);
        if !game_logic.players.contains_key(&0) {
            game_logic
                .players
                .insert(0, Player::new(0, Team::USA, "USA", true));
        }

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");

        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::Bombardment, Some(sc_id),));
        advance_battle_plan_door_to_active(&mut game_logic);

        // Force idle-scan complete at desired angle → enter Hold immediately.
        let desired = idle_scan_desired_angle_deg(0);
        let hold_start = game_logic.frame;
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.target = None;
            sc.ai_state = AIState::Idle;
            sc.status.attacking = false;
            sc.turret_angle_deg = desired;
            sc.turret_pitch_deg = STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG;
            sc.turret_idle_scanning = true;
            sc.turret_idle_scan_desired_angle_deg = desired;
            sc.turret_idle_scan_index = 0;
            sc.turret_holding = false;
            sc.turret_idle_recentering = false;
            sc.turret_hold_until_frame = 0;
            sc.turret_idle_scan_next_frame = 0;
        }
        game_logic.tick_battle_plan_door_residuals();
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(sc.turret_holding, "scan complete → HoldTurret residual");
            assert!(!sc.turret_idle_scanning);
            assert_eq!(
                sc.turret_hold_until_frame,
                hold_turret_until_frame(hold_start)
            );
            assert_eq!(STRATEGY_CENTER_RECENTER_TIME_FRAMES, 60);
            // Angles frozen at desired during hold.
            assert!((sc.turret_angle_deg - desired).abs() < 0.5);
        }
        assert!(game_logic.honesty_strategy_center_turret_hold_ok());
        assert_eq!(game_logic.battle_plans().turret_hold_start_count(), 1);

        // Mid-hold: angles still frozen, not recentering yet.
        game_logic.frame = hold_start.saturating_add(30);
        game_logic.tick_battle_plan_door_residuals();
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(sc.turret_holding, "must still be holding mid RecenterTime");
            assert!(!sc.turret_idle_recentering);
            assert!((sc.turret_angle_deg - desired).abs() < 0.5);
        }

        // Hold elapses → idle-recenter residual starts toward natural.
        game_logic.frame = hold_turret_until_frame(hold_start);
        game_logic.tick_battle_plan_door_residuals();
        assert!(
            game_logic.battle_plans().turret_hold_complete_count() >= 1,
            "HoldTurret residual must complete after RecenterTime"
        );
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(!sc.turret_holding, "hold complete clears holding");
            // Either mid idle-recenter or already finished (if already natural).
            assert!(
                sc.turret_idle_recentering
                    || turret_angles_are_natural(sc.turret_angle_deg, sc.turret_pitch_deg),
                "after hold must idle-recenter or already natural"
            );
            // First step toward natural: from desired (-60) toward -90 → -62.
            if sc.turret_idle_recentering {
                assert!(
                    (sc.turret_angle_deg - desired).abs() > 0.5
                        || (sc.turret_angle_deg - STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG).abs()
                            < 0.5,
                    "idle-recenter residual must step toward natural, got {}",
                    sc.turret_angle_deg
                );
            }
        }
        assert!(
            game_logic.battle_plans().turret_idle_recenter_start_count() >= 1
                || game_logic.honesty_strategy_center_turret_idle_recenter_ok(),
            "idle-recenter residual must start"
        );

        // Step enough frames for 30° at 2 deg/frame to restore natural.
        for _ in 0..40 {
            game_logic.frame = game_logic.frame.saturating_add(1);
            game_logic.tick_battle_plan_door_residuals();
            let sc = game_logic.find_object(sc_id).unwrap();
            if !sc.turret_idle_recentering
                && turret_angles_are_natural(sc.turret_angle_deg, sc.turret_pitch_deg)
            {
                break;
            }
        }
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                turret_angles_are_natural(sc.turret_angle_deg, sc.turret_pitch_deg),
                "idle-recenter residual must restore natural angles, a={} p={}",
                sc.turret_angle_deg,
                sc.turret_pitch_deg
            );
            assert!(!sc.turret_idle_recentering);
            // Next idle-scan scheduled with scan_index 1 → MaxIdleScanInterval 30.
            assert!(
                sc.turret_idle_scan_next_frame
                    >= game_logic
                        .frame
                        .saturating_add(idle_scan_interval_frames(1).saturating_sub(1)),
                "idle-recenter complete must reschedule next idle scan, next={} frame={}",
                sc.turret_idle_scan_next_frame,
                game_logic.frame
            );
        }
        assert!(
            game_logic.honesty_strategy_center_turret_idle_recenter_ok(),
            "idle-recenter residual honesty must record complete"
        );
    }

    /// Residual: TurretAI idle mood-target acquire + out-of-range clear.
    ///
    /// C++ friend_checkForIdleMoodTarget: Bombardment ACTIVE idle gun acquires
    /// enemy in StrategyCenterGun range band + Partition vision residual
    /// (VisionRange **400**), aims FirePitch, flags mood target.
    /// Mood target leaving range/vision clears so idle-scan can resume.
    /// Fail-closed: not full PartitionManager filter stack / pathfinder mood matrix.
    #[test]
    fn strategy_center_turret_mood_target_residual() {
        use crate::game_logic::host_strategy_center::{
            strategy_center_mood_vision_range, HostBattlePlan, STRATEGY_CENTER_BASE_VISION_RANGE,
            STRATEGY_CENTER_FIRE_PITCH_DEG, STRATEGY_CENTER_GUN_MIN_RANGE,
            STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG, STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG,
        };
        assert!((STRATEGY_CENTER_BASE_VISION_RANGE - 400.0).abs() < 0.001);
        assert!((strategy_center_mood_vision_range(false) - 400.0).abs() < 0.001);

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);
        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);
        if !game_logic.players.contains_key(&0) {
            game_logic
                .players
                .insert(0, Player::new(0, Team::USA, "USA", true));
        }

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::Bombardment, Some(sc_id),));
        advance_battle_plan_door_to_active(&mut game_logic);

        // Idle natural gun + enemy in gun range band (min 100).
        let enemy_id = game_logic
            .create_object(
                "TestTank",
                Team::GLA,
                Vec3::new(STRATEGY_CENTER_GUN_MIN_RANGE + 50.0, 0.0, 0.0),
            )
            .expect("enemy");
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.target = None;
            sc.ai_state = AIState::Idle;
            sc.status.attacking = false;
            sc.turret_mood_target = false;
            sc.turret_angle_deg = STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG;
            sc.turret_pitch_deg = STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG;
            sc.turret_idle_scanning = false;
            sc.turret_holding = false;
            sc.turret_idle_recentering = false;
        }
        game_logic.tick_battle_plan_door_residuals();
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                sc.turret_mood_target,
                "idle mood-target residual must flag m_targetWasSetByIdleMood"
            );
            assert_eq!(sc.target, Some(enemy_id));
            assert!(
                (sc.turret_pitch_deg - STRATEGY_CENTER_FIRE_PITCH_DEG).abs() < 0.01,
                "mood-target residual aims FirePitch, got {}",
                sc.turret_pitch_deg
            );
            // Yaw left natural toward enemy at +X.
            assert!(
                (sc.turret_angle_deg - STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG).abs() > 1.0
                    || sc.turret_angle_deg.abs() < 5.0,
                "mood-target residual must aim yaw at enemy, angle={}",
                sc.turret_angle_deg
            );
            assert!(!sc.turret_idle_scanning);
        }
        assert!(
            game_logic.honesty_strategy_center_turret_mood_target_ok(),
            "mood-target residual honesty must record acquire"
        );
        assert_eq!(
            game_logic.battle_plans().turret_mood_target_acquire_count(),
            1
        );

        // Move enemy out of max range → mood clear residual.
        {
            let e = game_logic.find_object_mut(enemy_id).expect("enemy");
            e.set_position(Vec3::new(900.0, 0.0, 0.0));
        }
        game_logic.tick_battle_plan_door_residuals();
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                !sc.turret_mood_target,
                "out-of-range residual must clear mood target"
            );
            assert!(sc.target.is_none());
        }
        assert!(
            game_logic.battle_plans().turret_mood_target_clear_count() >= 1,
            "mood-target clear honesty residual"
        );
    }

    /// Residual: TurretAI mood matrix Sleep/Passive + bone pitch drawable.
    ///
    /// C++ AttitudeType / getMoodMatrixActionAdjustment(MM_Action_Idle):
    /// - Sleep → IgnoreAll (no idle mood-target acquire)
    /// - Passive → WaitForAttack (only last_damage_source residual retaliate)
    /// - Normal → free acquire (covered by mood_target_residual)
    /// Bone pitch drawable residual exposes TurretAI pitch/yaw for presentation.
    /// VisionObjectName createVisionObject disabled in retail — honesty only.
    #[test]
    fn strategy_center_turret_mood_matrix_sleep_passive_residual() {
        use crate::game_logic::host_strategy_center::{
            strategy_center_turret_bone_drawable,
            strategy_center_vision_object_spawn_enabled_in_retail, HostAiAttitude, HostBattlePlan,
            STRATEGY_CENTER_FIRE_PITCH_DEG, STRATEGY_CENTER_GUN_MIN_RANGE,
            STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG, STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG,
        };

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);
        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);
        if !game_logic.players.contains_key(&0) {
            game_logic
                .players
                .insert(0, Player::new(0, Team::USA, "USA", true));
        }

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::Bombardment, Some(sc_id),));
        advance_battle_plan_door_to_active(&mut game_logic);

        let enemy_id = game_logic
            .create_object(
                "TestTank",
                Team::GLA,
                Vec3::new(STRATEGY_CENTER_GUN_MIN_RANGE + 50.0, 0.0, 0.0),
            )
            .expect("enemy");

        // --- Sleep: IgnoreAll → no mood-target acquire ---
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.target = None;
            sc.ai_state = AIState::Idle;
            sc.status.attacking = false;
            sc.turret_mood_target = false;
            sc.set_ai_attitude(HostAiAttitude::Sleep);
            sc.last_damage_source = None;
            sc.turret_angle_deg = STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG;
            sc.turret_pitch_deg = STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG;
            sc.turret_idle_scanning = false;
            sc.turret_holding = false;
            sc.turret_idle_recentering = false;
        }
        game_logic.tick_battle_plan_door_residuals();
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                !sc.turret_mood_target,
                "Sleep mood residual must not auto-acquire"
            );
            assert!(sc.target.is_none());
        }

        // --- Passive without last damage: WaitForAttack blocks free acquire ---
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.set_ai_attitude(HostAiAttitude::Passive);
            sc.last_damage_source = None;
            sc.turret_mood_target = false;
            sc.target = None;
            sc.ai_state = AIState::Idle;
            sc.status.attacking = false;
        }
        game_logic.tick_battle_plan_door_residuals();
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                !sc.turret_mood_target,
                "Passive without last damage must not free-acquire"
            );
        }

        // --- Passive with last damage source = enemy → retaliate residual ---
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.set_ai_attitude(HostAiAttitude::Passive);
            sc.last_damage_source = Some(enemy_id);
            sc.turret_mood_target = false;
            sc.target = None;
            sc.ai_state = AIState::Idle;
            sc.status.attacking = false;
        }
        game_logic.tick_battle_plan_door_residuals();
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                sc.turret_mood_target,
                "Passive WaitForAttack residual must retaliate vs last damage source"
            );
            assert_eq!(sc.target, Some(enemy_id));
            assert!(
                (sc.turret_pitch_deg - STRATEGY_CENTER_FIRE_PITCH_DEG).abs() < 0.01,
                "passive retaliate aims FirePitch, got {}",
                sc.turret_pitch_deg
            );
            // Bone pitch drawable residual from TurretAI angles.
            let bone =
                strategy_center_turret_bone_drawable(sc.turret_angle_deg, sc.turret_pitch_deg);
            assert!((bone.pitch_deg - STRATEGY_CENTER_FIRE_PITCH_DEG).abs() < 0.01);
            assert!(!bone.is_natural || bone.yaw_deg.abs() < 5.0);
        }

        // VisionObjectName createVisionObject disabled in retail C++.
        assert!(!strategy_center_vision_object_spawn_enabled_in_retail());
    }

    /// Residual: AmericaParachute OpenDist freefall → open residual path.
    ///
    /// Retail ParachuteOpenDist=100: freefall until fallen 100, then open chute
    /// (slower sink + ParachuteOpen audio residual). Fail-closed: not full
    /// bone PARA_COG / DeliverPayload matrix.
    #[test]
    fn eject_pilot_parachute_open_dist_residual() {
        use crate::game_logic::host_usa_pilot::{
            significantly_above_terrain_threshold, EJECT_PILOT_TEMPLATE, PARACHUTE_OPEN_DIST,
        };
        use crate::game_logic::VeterancyLevel;

        let mut game_logic = GameLogic::new();
        let mut humvee_tpl = ThingTemplate::new("AmericaVehicleHumvee");
        humvee_tpl
            .add_kind_of(KindOf::Vehicle)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(200.0);
        game_logic
            .templates
            .insert("AmericaVehicleHumvee".to_string(), humvee_tpl);

        let thr = significantly_above_terrain_threshold();
        let air_y = thr + PARACHUTE_OPEN_DIST + 80.0;
        let humvee_id = game_logic
            .create_object(
                "AmericaVehicleHumvee",
                Team::USA,
                Vec3::new(0.0, air_y, 0.0),
            )
            .expect("airborne humvee");
        {
            let h = game_logic.find_object_mut(humvee_id).expect("humvee");
            h.experience.level = VeterancyLevel::Veteran;
            h.status.airborne_target = true;
            let _ = h.take_damage(h.max_health * 2.0);
            h.status.destroyed = true;
        }
        game_logic.mark_object_for_destruction(humvee_id, Some(Team::GLA));
        game_logic.process_destroy_list();

        let pilot_id = game_logic
            .objects
            .iter()
            .find(|(_, o)| o.is_alive() && o.template_name == EJECT_PILOT_TEMPLATE)
            .map(|(id, _)| *id)
            .expect("ejected pilot");
        let start_y = game_logic.find_object(pilot_id).unwrap().get_position().y;
        assert!(
            !game_logic
                .find_object(pilot_id)
                .unwrap()
                .is_parachute_open(),
            "starts freefall closed"
        );

        // Tick freefall until OpenDist residual opens chute (before land).
        let ids = [pilot_id];
        let mut opened_y = None;
        for _ in 0..20 {
            game_logic.update_ai(&ids, 1.0 / 30.0);
            let p = game_logic.find_object(pilot_id).expect("pilot");
            if p.is_parachute_open() {
                opened_y = Some(p.get_position().y);
                break;
            }
            assert!(
                p.is_parachuting(),
                "must still be parachuting during freefall"
            );
        }
        let opened_y = opened_y.expect("OpenDist residual must open chute");
        assert!(
            game_logic.honesty_pilot_parachute_open_ok(),
            "parachute open honesty"
        );
        let fallen = start_y - opened_y;
        assert!(
            fallen + 0.5 >= PARACHUTE_OPEN_DIST,
            "chute open residual after ≥OpenDist freefall, fallen={fallen}"
        );
        assert!(
            !game_logic.honesty_pilot_parachute_land_ok(),
            "must not land on the open frame (still elevated)"
        );

        // Finish landing residual.
        for _ in 0..100 {
            game_logic.update_ai(&ids, 1.0 / 30.0);
            if game_logic.honesty_pilot_parachute_land_ok() {
                break;
            }
        }
        assert!(game_logic.honesty_pilot_parachute_land_ok());
        assert!(
            game_logic
                .find_object(pilot_id)
                .unwrap()
                .get_position()
                .y
                .abs()
                < 0.1
        );
    }

    /// Residual: AmericaParachute pitch/roll spring-damper sway residual.
    ///
    /// While chute open: seed ±½ Pitch/RollRateMax, spring/damper with
    /// ParachuteLocomotor stiffness/damping + LowAltitudeDamping near ground.
    /// Fail-closed: not full bone PARA_COG / rider sway / DeliverPayload matrix.
    #[test]
    fn eject_pilot_parachute_pitch_roll_sway_residual() {
        use crate::game_logic::host_usa_pilot::{
            parachute_initial_pitch_rate, parachute_initial_roll_rate,
            significantly_above_terrain_threshold, EJECT_PILOT_TEMPLATE, PARACHUTE_OPEN_DIST,
        };
        use crate::game_logic::VeterancyLevel;

        let mut game_logic = GameLogic::new();
        let mut humvee_tpl = ThingTemplate::new("AmericaVehicleHumvee");
        humvee_tpl
            .add_kind_of(KindOf::Vehicle)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(200.0);
        game_logic
            .templates
            .insert("AmericaVehicleHumvee".to_string(), humvee_tpl);

        let thr = significantly_above_terrain_threshold();
        // Tall freefall so chute opens well above ground and sway has time to step.
        let air_y = thr + PARACHUTE_OPEN_DIST + 200.0;
        let humvee_id = game_logic
            .create_object(
                "AmericaVehicleHumvee",
                Team::USA,
                Vec3::new(0.0, air_y, 0.0),
            )
            .expect("airborne humvee");
        {
            let h = game_logic.find_object_mut(humvee_id).expect("humvee");
            h.experience.level = VeterancyLevel::Veteran;
            h.status.airborne_target = true;
            let _ = h.take_damage(h.max_health * 2.0);
            h.status.destroyed = true;
        }
        game_logic.mark_object_for_destruction(humvee_id, Some(Team::GLA));
        game_logic.process_destroy_list();

        let pilot_id = game_logic
            .objects
            .iter()
            .find(|(_, o)| o.is_alive() && o.template_name == EJECT_PILOT_TEMPLATE)
            .map(|(id, _)| *id)
            .expect("ejected pilot");
        let ids = [pilot_id];

        // Freefall residual: pitch/roll stay 0 until open.
        for _ in 0..5 {
            game_logic.update_ai(&ids, 1.0 / 30.0);
            let p = game_logic.find_object(pilot_id).expect("pilot");
            if p.is_parachute_open() {
                break;
            }
            assert!(
                p.parachute_pitch().abs() < 1e-6 && p.parachute_roll().abs() < 1e-6,
                "freefall residual must not sway before chute opens"
            );
        }

        // Open residual then step pitch/roll spring-damper.
        let mut saw_open = false;
        let mut saw_non_zero_sway = false;
        for _ in 0..80 {
            game_logic.update_ai(&ids, 1.0 / 30.0);
            let p = game_logic.find_object(pilot_id).expect("pilot");
            if p.is_parachute_open() {
                saw_open = true;
                // Open frame seeds rates; subsequent frames integrate angles.
                if p.parachute_pitch().abs() > 1e-6 || p.parachute_roll().abs() > 1e-6 {
                    saw_non_zero_sway = true;
                    break;
                }
            }
            if game_logic.honesty_pilot_parachute_land_ok() {
                break;
            }
        }
        assert!(saw_open, "OpenDist residual must open chute for sway");
        assert!(
            saw_non_zero_sway,
            "pitch/roll sway residual must leave zero after open frames"
        );
        assert!(
            game_logic.honesty_pilot_parachute_sway_ok(),
            "sway honesty residual must tick while chute open"
        );
        // Seed residual honesty: open sets deterministic mid rates.
        let open_seed_ok =
            parachute_initial_pitch_rate().abs() > 0.0 && parachute_initial_roll_rate().abs() > 0.0;
        assert!(open_seed_ok, "deterministic mid pitch/roll rate seed");

        // Land residual clears sway angles.
        for _ in 0..200 {
            game_logic.update_ai(&ids, 1.0 / 30.0);
            if game_logic.honesty_pilot_parachute_land_ok() {
                break;
            }
        }
        assert!(game_logic.honesty_pilot_parachute_land_ok());
        let landed = game_logic.find_object(pilot_id).expect("pilot");
        assert!(!landed.is_parachuting(), "land residual clears parachuting");
        assert!(
            landed.parachute_pitch().abs() < 1e-6 && landed.parachute_roll().abs() < 1e-6,
            "land residual must clear pitch/roll sway state"
        );
    }

    /// Residual: Bombardment plan enables StrategyCenterGun turret auto-fire.
    ///
    /// C++ enableTurret(true) on Bombardment residual:
    /// PrimaryDamage 200 / r25, range 400, min 100, Delay 7000ms.
    /// Fail-closed: not full natural-position recenter / pack animation.
    #[test]
    fn strategy_center_bombardment_turret_fire_residual() {
        use crate::game_logic::host_strategy_center::{
            HostBattlePlan, STRATEGY_CENTER_GUN_DAMAGE, STRATEGY_CENTER_GUN_MIN_RANGE,
            STRATEGY_CENTER_GUN_RANGE,
        };

        let mut game_logic = GameLogic::new();

        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);

        ensure_test_tank_template(&mut game_logic);

        // Ensure USA player exists for player_id_for_team residual gate.
        if !game_logic.players.contains_key(&0) {
            game_logic
                .players
                .insert(0, Player::new(0, Team::USA, "USA", true));
        } else if let Some(p) = game_logic.players.get_mut(&0) {
            p.team = Team::USA;
        }

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");

        // Without Bombardment: no StrategyCenterGun residual.
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(sc.weapon.is_none(), "turret disabled without Bombardment");
        }

        // Enemy in range band (min 100, max 400).
        let enemy_id = game_logic
            .create_object(
                "TestTank",
                Team::GLA,
                Vec3::new(STRATEGY_CENTER_GUN_MIN_RANGE + 50.0, 0.0, 0.0),
            )
            .expect("enemy");
        {
            let e = game_logic.find_object_mut(enemy_id).expect("enemy");
            e.health.current = e.health.maximum; // full
        }
        let enemy_hp_before = game_logic.find_object(enemy_id).unwrap().health.current;

        // Too-close enemy residual (inside min range) must not be preferred when
        // a legal in-band target exists; still create for range-band honesty.
        let close_id = game_logic
            .create_object("TestTank", Team::GLA, Vec3::new(20.0, 0.0, 0.0))
            .expect("close enemy");
        let close_hp_before = game_logic.find_object(close_id).unwrap().health.current;

        assert!(!game_logic.honesty_battle_plan_turret_fire_ok());

        // Activate Bombardment → equip StrategyCenterGun only after unpack ACTIVE.
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::Bombardment, Some(sc_id),));
        assert!(
            game_logic.find_object(sc_id).unwrap().weapon.is_none(),
            "turret must not equip during UNPACKING residual"
        );
        advance_battle_plan_door_to_active(&mut game_logic);
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            let w = sc
                .weapon
                .as_ref()
                .expect("Bombardment ACTIVE must equip StrategyCenterGun");
            assert!(
                (w.damage - STRATEGY_CENTER_GUN_DAMAGE).abs() < 0.001,
                "StrategyCenterGun damage residual 200"
            );
            assert!(
                (w.range - STRATEGY_CENTER_GUN_RANGE).abs() < 0.001,
                "StrategyCenterGun range residual 400"
            );
            assert!(
                (w.min_range - STRATEGY_CENTER_GUN_MIN_RANGE).abs() < 0.001,
                "StrategyCenterGun min range residual 100"
            );
        }

        // Fire residual (force readiness: last_fire_time far past).
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            if let Some(w) = sc.weapon.as_mut() {
                w.last_fire_time = -100.0;
            }
            sc.ai_state = AIState::Idle;
        }
        // Natural angles before fire residual.
        {
            use crate::game_logic::host_strategy_center::{
                turret_angles_are_natural, STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG,
                STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG,
            };
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                turret_angles_are_natural(sc.turret_angle_deg, sc.turret_pitch_deg),
                "turret residual starts at NaturalTurretAngle/Pitch"
            );
            assert!((sc.turret_angle_deg - STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG).abs() < 0.01);
            assert!((sc.turret_pitch_deg - STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG).abs() < 0.01);
        }

        game_logic.try_strategy_center_bombardment_turret_fire(sc_id);

        assert!(
            game_logic.honesty_battle_plan_turret_fire_ok(),
            "Bombardment turret residual must record fire honesty"
        );
        assert!(game_logic.battle_plans().turret_fire_count() >= 1);
        // Pitch/yaw aim residual: after fire, angles leave natural toward target.
        {
            use crate::game_logic::host_strategy_center::{
                turret_angles_are_natural, STRATEGY_CENTER_FIRE_PITCH_DEG,
            };
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                !turret_angles_are_natural(sc.turret_angle_deg, sc.turret_pitch_deg),
                "fire residual must aim turret off NaturalTurretAngle"
            );
            assert!(
                (sc.turret_pitch_deg - STRATEGY_CENTER_FIRE_PITCH_DEG).abs() < 0.01,
                "FirePitch residual 45"
            );
            assert!(
                game_logic.honesty_strategy_center_turret_aim_ok(),
                "turret aim residual honesty"
            );
        }

        let enemy_hp_after = game_logic.find_object(enemy_id).unwrap().health.current;
        assert!(
            enemy_hp_after < enemy_hp_before - 50.0,
            "in-range enemy must take StrategyCenterGun residual damage, before={enemy_hp_before} after={enemy_hp_after}"
        );

        // Close enemy may take splash if within 25 of impact (impact is on far enemy at x=150).
        // At x=20 vs impact x=150 → no splash. Must remain undamaged by min-range gate.
        let close_hp_after = game_logic.find_object(close_id).unwrap().health.current;
        assert!(
            (close_hp_after - close_hp_before).abs() < 0.001,
            "min-range residual must not target close enemy as primary"
        );

        // Switch to HoldTheLine → PACKING clears turret residual immediately.
        // Ensure turret is natural (busy + pitch/yaw) so pack starts without recenter.
        {
            use crate::game_logic::host_strategy_center::{
                STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG, STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG,
            };
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.target = None;
            sc.ai_state = AIState::Idle;
            sc.status.attacking = false;
            sc.turret_angle_deg = STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG;
            sc.turret_pitch_deg = STRATEGY_CENTER_NATURAL_TURRET_PITCH_DEG;
            if let Some(w) = sc.weapon.as_mut() {
                w.last_fire_time = -100.0;
            }
        }
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::HoldTheLine, Some(sc_id),));
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                sc.weapon.is_none(),
                "PACKING residual must disable StrategyCenterGun"
            );
        }
    }

    /// Residual: Strategy Center StealthDetectorUpdate enable stack (S&D).
    ///
    /// Retail ModuleTag_16: DetectionRange **500**, DetectionRate **500**ms →
    /// **15** frames, InitiallyDisabled **Yes**. SearchAndDestroy →
    /// setSDEnabled(true); leaving S&D → setSDEnabled(false). DetectionRate
    /// residual: immediate first scan, then rate-gated with
    /// markAsDetected(rate+1). VisionObjectName spawn residual is fail-closed
    /// (createVisionObject disabled in retail C++).
    #[test]
    fn strategy_center_stealth_detector_enable_residual() {
        use crate::game_logic::host_strategy_center::{
            HostBattlePlan, STRATEGY_CENTER_STEALTH_DETECTION_RANGE,
            STRATEGY_CENTER_STEALTH_DETECTION_RATE_FRAMES,
        };

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);
        ensure_test_player_for_team(&mut game_logic, Team::USA);
        ensure_test_player_for_team(&mut game_logic, Team::China);

        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        sc_template.sight_range = 400.0;
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");
        {
            // InitiallyDisabled residual: Strategy Center is not a detector until S&D.
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.is_detector = false;
            sc.detection_range = 0.0;
            sc.object_type = ObjectType::Building;
        }

        // Stealthed enemy inside DetectionRange 500.
        let near_id = game_logic
            .create_object("TestTank", Team::China, Vec3::new(400.0, 0.0, 0.0))
            .expect("near stealthed");
        {
            let e = game_logic.find_object_mut(near_id).expect("near");
            e.apply_grant_stealth();
            assert!(e.is_effectively_stealthed());
        }
        // Stealthed enemy outside DetectionRange 500.
        let far_id = game_logic
            .create_object("TestTank", Team::China, Vec3::new(600.0, 0.0, 0.0))
            .expect("far stealthed");
        {
            let e = game_logic.find_object_mut(far_id).expect("far");
            e.apply_grant_stealth();
        }

        // Without S&D: detector off → no residual detect.
        assert!(!game_logic.find_object(sc_id).unwrap().is_detector);
        game_logic.update_stealth_and_detection();
        assert!(
            game_logic
                .find_object(near_id)
                .unwrap()
                .is_effectively_stealthed(),
            "InitiallyDisabled residual must not detect before S&D"
        );

        // Activate SearchAndDestroy → DetectionRange 500 + is_detector after ACTIVE.
        assert!(!game_logic.honesty_battle_plan_stealth_detector_ok());
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::SearchAndDestroy, Some(sc_id),));
        assert!(
            !game_logic.find_object(sc_id).unwrap().is_detector,
            "StealthDetector must wait for unpack ACTIVE residual"
        );
        advance_battle_plan_door_to_active(&mut game_logic);
        assert!(
            game_logic.honesty_battle_plan_stealth_detector_ok(),
            "S&D ACTIVE must record StealthDetector enable honesty"
        );
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(sc.is_detector, "S&D must enable StealthDetector residual");
            assert!(
                (sc.detection_range - STRATEGY_CENTER_STEALTH_DETECTION_RANGE).abs() < 0.1,
                "DetectionRange residual must be 500, got {}",
                sc.detection_range
            );
            assert_eq!(
                sc.detection_rate_frames, STRATEGY_CENTER_STEALTH_DETECTION_RATE_FRAMES,
                "DetectionRate residual must be 15 frames"
            );
            assert_eq!(
                sc.next_detection_scan_frame, 0,
                "setSDEnabled residual first scan must be immediate"
            );
        }

        game_logic.update_stealth_and_detection();
        assert!(
            game_logic.honesty_stealth_detector_rate_ok(),
            "DetectionRate residual must record scan honesty"
        );
        assert!(
            !game_logic
                .find_object(near_id)
                .unwrap()
                .is_effectively_stealthed(),
            "near stealthed enemy must be detected at DetectionRange 500"
        );
        assert!(
            game_logic
                .find_object(far_id)
                .unwrap()
                .is_effectively_stealthed(),
            "far stealthed enemy beyond 500 must remain undetected"
        );
        // After first scan, next DetectionRate wake is frame + 15.
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert_eq!(
                sc.next_detection_scan_frame,
                game_logic.frame + STRATEGY_CENTER_STEALTH_DETECTION_RATE_FRAMES,
                "DetectionRate residual must sleep 15 frames after scan"
            );
        }

        // Leave S&D → PACKING setSDEnabled(false) residual.
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::Bombardment, Some(sc_id),));
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert!(
                !sc.is_detector,
                "PACKING residual must disable StealthDetector"
            );
            assert!(
                sc.detection_range.abs() < 0.1,
                "PACKING residual must clear DetectionRange residual"
            );
            assert_eq!(
                sc.detection_rate_frames, 0,
                "PACKING residual must clear DetectionRate residual"
            );
        }
        assert!(
            game_logic.battle_plans().stealth_detector_disable_count() >= 1,
            "must record StealthDetector disable honesty"
        );

        // After disable: clear detected and re-stealth for residual recheck.
        {
            let e = game_logic.find_object_mut(near_id).expect("near");
            e.apply_grant_stealth();
        }
        game_logic.update_stealth_and_detection();
        assert!(
            game_logic
                .find_object(near_id)
                .unwrap()
                .is_effectively_stealthed(),
            "disabled StealthDetector residual must not detect"
        );
    }

    /// Residual: StealthDetectorUpdate DetectionRate sleep phasing (Strategy Center).
    ///
    /// Retail DetectionRate **500**ms → **15** frames; markAsDetected(rate+1=**16**).
    /// First scan immediate on setSDEnabled; subsequent scans rate-gated.
    /// Fail-closed: VisionObjectName spawn residual still not claimed.
    #[test]
    fn strategy_center_stealth_detector_detection_rate_residual() {
        use crate::game_logic::host_strategy_center::{
            HostBattlePlan, STRATEGY_CENTER_STEALTH_DETECTION_HOLD_FRAMES,
            STRATEGY_CENTER_STEALTH_DETECTION_RATE_FRAMES,
        };

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);
        ensure_test_player_for_team(&mut game_logic, Team::USA);
        ensure_test_player_for_team(&mut game_logic, Team::China);

        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        sc_template.sight_range = 400.0;
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");
        {
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.is_detector = false;
            sc.detection_range = 0.0;
            sc.object_type = ObjectType::Building;
        }

        let enemy_id = game_logic
            .create_object("TestTank", Team::China, Vec3::new(200.0, 0.0, 0.0))
            .expect("stealthed enemy");
        {
            let e = game_logic.find_object_mut(enemy_id).expect("enemy");
            e.apply_grant_stealth();
        }

        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::SearchAndDestroy, Some(sc_id),));
        advance_battle_plan_door_to_active(&mut game_logic);

        // Frame 0: immediate first DetectionRate residual scan.
        game_logic.frame = 0;
        let scans_before = game_logic.stealth_detector_rate_scans();
        game_logic.update_stealth_and_detection();
        assert!(
            game_logic.stealth_detector_rate_scans() > scans_before,
            "first DetectionRate residual scan must fire immediately"
        );
        {
            let e = game_logic.find_object(enemy_id).expect("enemy");
            assert!(
                e.status.detected,
                "first scan must detect in-range stealthed"
            );
            assert_eq!(
                e.detection_expires_frame, STRATEGY_CENTER_STEALTH_DETECTION_HOLD_FRAMES,
                "markAsDetected(rate+1) residual hold must be 16 frames"
            );
        }
        {
            let sc = game_logic.find_object(sc_id).expect("sc");
            assert_eq!(
                sc.next_detection_scan_frame, STRATEGY_CENTER_STEALTH_DETECTION_RATE_FRAMES,
                "next scan residual at frame 15"
            );
        }

        // Mid-rate frames: detector sleeps — no new rate scan.
        let scans_after_first = game_logic.stealth_detector_rate_scans();
        game_logic.frame = 7;
        game_logic.update_stealth_and_detection();
        assert_eq!(
            game_logic.stealth_detector_rate_scans(),
            scans_after_first,
            "DetectionRate residual must not re-scan mid-sleep"
        );

        // Next DetectionRate wake at frame 15.
        game_logic.frame = STRATEGY_CENTER_STEALTH_DETECTION_RATE_FRAMES;
        game_logic.update_stealth_and_detection();
        assert!(
            game_logic.stealth_detector_rate_scans() > scans_after_first,
            "DetectionRate residual must re-scan after 15 frames"
        );
        {
            let e = game_logic.find_object(enemy_id).expect("enemy");
            assert!(
                e.status.detected,
                "rate re-scan must refresh detected residual"
            );
            assert_eq!(
                e.detection_expires_frame,
                STRATEGY_CENTER_STEALTH_DETECTION_RATE_FRAMES
                    + STRATEGY_CENTER_STEALTH_DETECTION_HOLD_FRAMES,
                "refresh hold residual = scan_frame + rate + 1"
            );
        }
        assert!(game_logic.honesty_stealth_detector_rate_ok());
    }

    /// Residual: BattlePlan pack/unpack door model-condition / 7s animation.
    ///
    /// Retail AnimationTime **7000**ms → **210** frames; TransitionIdleTime **0**.
    /// DOOR_1 Bombardment / DOOR_2 HoldTheLine / DOOR_3 SearchAndDestroy.
    /// OPENING → WAITING_TO_CLOSE after 210 frames; plan switch → CLOSING then
    /// new OPENING. Army buffs apply only on ACTIVE (delayed setBattlePlan residual).
    #[test]
    fn strategy_center_battle_plan_door_animation_residual() {
        use crate::game_logic::host_strategy_center::{
            HostBattlePlan, HostBattlePlanDoor, HostBattlePlanTransition,
            BATTLE_PLAN_ANIMATION_FRAMES,
        };

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);
        ensure_test_player_for_team(&mut game_logic, Team::USA);

        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");
        let ally_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(10.0, 0.0, 0.0))
            .expect("ally");
        {
            let u = game_logic.find_object_mut(ally_id).expect("ally");
            u.weapon = Some(Weapon {
                damage: 20.0,
                range: 100.0,
                reload_time: 0.1,
                last_fire_time: -10.0,
                ..Weapon::default()
            });
        }

        assert!(!game_logic.honesty_battle_plan_door_ok());

        // First select Bombardment: door OPENING residual; army buffs deferred.
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::Bombardment, Some(sc_id),));
        assert!(
            game_logic.honesty_battle_plan_door_ok(),
            "door residual must start on plan select"
        );
        {
            let state = game_logic
                .battle_plans()
                .door_state_for_center(sc_id)
                .expect("door state");
            assert_eq!(state.status, HostBattlePlanTransition::Unpacking);
            assert_eq!(state.door, HostBattlePlanDoor::Door1Opening);
            assert_eq!(
                state.next_ready_frame,
                game_logic.frame + BATTLE_PLAN_ANIMATION_FRAMES
            );
        }
        assert!(
            !game_logic
                .find_object(ally_id)
                .unwrap()
                .weapon_bonus_battle_plan_bombardment,
            "army buff residual must wait for unpack ACTIVE"
        );
        assert!(!game_logic.honesty_battle_plan_door_active_ok());

        // Advance AnimationTime frames → WAITING_TO_CLOSE + setBattlePlan.
        game_logic.frame = game_logic
            .frame
            .saturating_add(BATTLE_PLAN_ANIMATION_FRAMES);
        game_logic.tick_battle_plan_door_residuals();
        assert!(
            game_logic.honesty_battle_plan_door_active_ok(),
            "door residual must reach ACTIVE after AnimationTime"
        );
        assert!(
            game_logic
                .find_object(ally_id)
                .unwrap()
                .weapon_bonus_battle_plan_bombardment,
            "ACTIVE residual must apply Bombardment army buffs"
        );
        {
            let state = game_logic
                .battle_plans()
                .door_state_for_center(sc_id)
                .expect("door state");
            assert_eq!(state.status, HostBattlePlanTransition::Active);
            assert_eq!(state.door, HostBattlePlanDoor::Door1WaitingToClose);
        }

        // Plan switch → PACKING door1 CLOSING residual; clears buffs immediately.
        let pack_frame = game_logic.frame;
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::HoldTheLine, Some(sc_id),));
        {
            let state = game_logic
                .battle_plans()
                .door_state_for_center(sc_id)
                .expect("door state");
            assert_eq!(state.status, HostBattlePlanTransition::Packing);
            assert_eq!(state.door, HostBattlePlanDoor::Door1Closing);
            assert_eq!(
                state.next_ready_frame,
                pack_frame + BATTLE_PLAN_ANIMATION_FRAMES
            );
        }
        assert!(
            !game_logic
                .find_object(ally_id)
                .unwrap()
                .has_battle_plan_bonus(),
            "PACKING residual must clear army buffs (setBattlePlan NONE)"
        );

        // Pack complete (TransitionIdleTime 0) → unpack HoldTheLine DOOR_2 OPENING.
        game_logic.frame = pack_frame.saturating_add(BATTLE_PLAN_ANIMATION_FRAMES);
        game_logic.tick_battle_plan_door_residuals();
        {
            let state = game_logic
                .battle_plans()
                .door_state_for_center(sc_id)
                .expect("door state");
            assert_eq!(state.status, HostBattlePlanTransition::Unpacking);
            assert_eq!(state.door, HostBattlePlanDoor::Door2Opening);
        }

        // SearchAndDestroy door residual DOOR_3 after Active.
        game_logic.frame = game_logic
            .frame
            .saturating_add(BATTLE_PLAN_ANIMATION_FRAMES);
        game_logic.tick_battle_plan_door_residuals();
        // HoldTheLine now ACTIVE.
        assert!(
            game_logic
                .find_object(ally_id)
                .unwrap()
                .weapon_bonus_battle_plan_hold_the_line
        );
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::SearchAndDestroy, Some(sc_id),));
        // Pack HoldTheLine door2 closing first.
        {
            let state = game_logic
                .battle_plans()
                .door_state_for_center(sc_id)
                .expect("door state");
            assert_eq!(state.door, HostBattlePlanDoor::Door2Closing);
        }
        game_logic.frame = game_logic
            .frame
            .saturating_add(BATTLE_PLAN_ANIMATION_FRAMES);
        game_logic.tick_battle_plan_door_residuals();
        {
            let state = game_logic
                .battle_plans()
                .door_state_for_center(sc_id)
                .expect("door state");
            assert_eq!(state.status, HostBattlePlanTransition::Unpacking);
            assert_eq!(state.door, HostBattlePlanDoor::Door3Opening);
        }
    }

    /// Residual: delayed ACTIVE-after-unpack setBattlePlan + Bombardment recenter.
    ///
    /// C++ setStatus(ACTIVE) → setBattlePlan(plan); setStatus(PACKING) →
    /// setBattlePlan(NONE)+paralyze. Leaving Bombardment with non-natural turret
    /// recenters (30 frames) before pack.
    #[test]
    fn strategy_center_delayed_set_battle_plan_and_turret_recenter_residual() {
        use crate::game_logic::host_strategy_center::{
            HostBattlePlan, HostBattlePlanTransition, BATTLE_PLAN_ANIMATION_FRAMES,
            BATTLE_PLAN_TURRET_RECENTER_FRAMES,
        };

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);
        ensure_test_player_for_team(&mut game_logic, Team::USA);

        let mut sc_template = ThingTemplate::new("AmericaStrategyCenter");
        sc_template
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::FSStrategyCenter)
            .add_kind_of(KindOf::Selectable)
            .set_health(1500.0);
        game_logic
            .templates
            .insert("AmericaStrategyCenter".to_string(), sc_template);

        let sc_id = game_logic
            .create_object("AmericaStrategyCenter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("strategy center");
        let ally_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(10.0, 0.0, 0.0))
            .expect("ally");
        {
            let u = game_logic.find_object_mut(ally_id).expect("ally");
            u.weapon = Some(Weapon {
                damage: 20.0,
                range: 100.0,
                reload_time: 0.1,
                last_fire_time: -10.0,
                ..Weapon::default()
            });
        }

        assert!(!game_logic.honesty_battle_plan_delayed_active_ok());
        assert!(!game_logic.honesty_battle_plan_turret_recenter_ok());

        // Select Bombardment — no buffs until ACTIVE.
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::Bombardment, Some(sc_id),));
        assert!(!game_logic
            .find_object(ally_id)
            .unwrap()
            .has_battle_plan_bonus());
        advance_battle_plan_door_to_active(&mut game_logic);
        assert!(game_logic.honesty_battle_plan_delayed_active_ok());
        assert!(
            game_logic
                .find_object(ally_id)
                .unwrap()
                .weapon_bonus_battle_plan_bombardment
        );
        assert!(game_logic.find_object(sc_id).unwrap().weapon.is_some());

        // Make turret non-natural via pitch/yaw residual (off NaturalTurretAngle)
        // plus busy gate, then switch plan.
        let fire_time = game_logic.frame as f32 * LOGIC_FRAME_TIMESTEP;
        {
            use crate::game_logic::host_strategy_center::STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG;
            let sc = game_logic.find_object_mut(sc_id).expect("sc");
            sc.ai_state = AIState::Attacking;
            sc.status.attacking = true;
            sc.target = Some(ally_id);
            // 60° off natural → 30 frames at 2 deg/frame residual.
            sc.turret_angle_deg = STRATEGY_CENTER_NATURAL_TURRET_ANGLE_DEG + 60.0;
            sc.turret_pitch_deg = 45.0;
            if let Some(w) = sc.weapon.as_mut() {
                w.last_fire_time = fire_time;
            }
        }
        let switch_frame = game_logic.frame;
        assert!(game_logic.activate_battle_plan(0, HostBattlePlan::HoldTheLine, Some(sc_id),));
        assert!(
            game_logic.honesty_battle_plan_turret_recenter_ok(),
            "non-natural Bombardment turret must start recenter residual"
        );
        {
            let state = game_logic
                .battle_plans()
                .door_state_for_center(sc_id)
                .expect("door");
            assert!(state.centering_turret);
            assert_eq!(state.status, HostBattlePlanTransition::Active);
            assert_eq!(
                state.next_ready_frame,
                switch_frame + BATTLE_PLAN_TURRET_RECENTER_FRAMES,
                "60° yaw delta → 30 frames at TurretTurnRate 60 deg/s"
            );
        }
        // During recenter: Bombardment buffs still active (not packed yet).
        assert!(
            game_logic
                .find_object(ally_id)
                .unwrap()
                .weapon_bonus_battle_plan_bombardment,
            "recenter residual must not clear army buffs until pack"
        );
        assert!(game_logic.find_object(sc_id).unwrap().weapon.is_some());

        // Step recenter frames: turret angles advance toward natural each tick.
        // 60° at 2 deg/frame → exactly 30 steps to NaturalTurretAngle.
        {
            use crate::game_logic::host_strategy_center::turret_angles_are_natural;
            let mut last_angle = game_logic.find_object(sc_id).unwrap().turret_angle_deg;
            for step in 1..=BATTLE_PLAN_TURRET_RECENTER_FRAMES {
                game_logic.frame = switch_frame.saturating_add(step);
                let centering = game_logic
                    .battle_plans()
                    .door_state_for_center(sc_id)
                    .map(|s| s.centering_turret)
                    .unwrap_or(false);
                assert!(centering, "must still be recentering at step {step}");
                if let Some(sc) = game_logic.find_object_mut(sc_id) {
                    let (a, p) =
                        crate::game_logic::host_strategy_center::step_turret_toward_natural(
                            sc.turret_angle_deg,
                            sc.turret_pitch_deg,
                        );
                    sc.turret_angle_deg = a;
                    sc.turret_pitch_deg = p;
                }
                let a_now = game_logic.find_object(sc_id).unwrap().turret_angle_deg;
                // Angle should move toward natural (-90 from -30) or already natural.
                assert!(
                    a_now <= last_angle + 0.01,
                    "recenter residual must step yaw toward natural, {last_angle} → {a_now}"
                );
                last_angle = a_now;
            }
            // After full recenter frames, angles natural residual.
            assert!(
                turret_angles_are_natural(
                    game_logic.find_object(sc_id).unwrap().turret_angle_deg,
                    game_logic.find_object(sc_id).unwrap().turret_pitch_deg,
                ),
                "recenter residual must restore NaturalTurretAngle/Pitch, angle={} pitch={}",
                game_logic.find_object(sc_id).unwrap().turret_angle_deg,
                game_logic.find_object(sc_id).unwrap().turret_pitch_deg,
            );
        }

        // Recenter complete → PACKING clears buffs + paralyzes.
        // tick_battle_plan_door_residuals also steps angles once more (harmless at natural).
        game_logic.frame = switch_frame.saturating_add(BATTLE_PLAN_TURRET_RECENTER_FRAMES);
        game_logic.tick_battle_plan_door_residuals();
        assert!(game_logic.honesty_battle_plan_pack_clear_ok());
        {
            let state = game_logic
                .battle_plans()
                .door_state_for_center(sc_id)
                .expect("door");
            assert_eq!(state.status, HostBattlePlanTransition::Packing);
            assert!(!state.centering_turret);
        }
        assert!(
            !game_logic
                .find_object(ally_id)
                .unwrap()
                .has_battle_plan_bonus(),
            "PACKING after recenter must clear army buffs"
        );
        assert!(game_logic.find_object(sc_id).unwrap().weapon.is_none());
        assert!(
            game_logic
                .find_object(ally_id)
                .unwrap()
                .is_paralyzed_disabled(),
            "PACKING residual must paralyze army (setBattlePlan NONE)"
        );

        // Pack+unpack → HoldTheLine ACTIVE.
        game_logic.frame = game_logic
            .frame
            .saturating_add(BATTLE_PLAN_ANIMATION_FRAMES);
        game_logic.tick_battle_plan_door_residuals();
        game_logic.frame = game_logic
            .frame
            .saturating_add(BATTLE_PLAN_ANIMATION_FRAMES);
        game_logic.tick_battle_plan_door_residuals();
        assert!(
            game_logic
                .find_object(ally_id)
                .unwrap()
                .weapon_bonus_battle_plan_hold_the_line,
            "HoldTheLine buffs after full pack+unpack ACTIVE residual"
        );
        assert_eq!(
            game_logic.battle_plans().active_plan_for_player(0),
            Some(HostBattlePlan::HoldTheLine)
        );
    }

    /// Residual: Emergency Repair special power heals damaged ally vehicles in radius.
    ///
    /// C++ SuperweaponEmergencyRepair → SUPERWEAPON_RepairVehicles1 →
    /// RepairVehiclesInArea_InvisibleMarker_Level1 AutoHealBehavior SingleBurst
    /// HealingAmount=100 / Radius=100 / KindOf=VEHICLE.
    /// Fail-closed: not full OCL marker / RepairCloud / science tier matrix.
    #[test]
    fn emergency_repair_residual_heals_damaged_ally_vehicles() {
        use crate::command_system::{CommandType, GameCommand, PowerTarget, SpecialPowerType};
        use crate::game_logic::host_emergency_repair::{
            HostEmergencyRepairLevel, HOST_EMERGENCY_REPAIR_RADIUS,
        };

        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);
        ensure_test_infantry_template(&mut game_logic);

        // Caster + ally on USA (Emergency Repair is multi-faction residual).
        let caster_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(500.0, 0.0, 500.0))
            .expect("caster");
        {
            let caster = game_logic.find_object_mut(caster_id).expect("caster");
            caster.special_power_ready = true;
            caster.special_power_cooldown_remaining = 0.0;
        }

        let ally_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(10.0, 0.0, 0.0))
            .expect("ally");
        let full_hp_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(20.0, 0.0, 0.0))
            .expect("full hp ally");
        let far_ally_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(400.0, 0.0, 0.0))
            .expect("far ally");
        let enemy_id = game_logic
            .create_object("TestTank", Team::GLA, Vec3::new(15.0, 0.0, 0.0))
            .expect("enemy");
        let infantry_id = game_logic
            .create_object("TestInfantry", Team::USA, Vec3::new(25.0, 0.0, 0.0))
            .expect("infantry");

        // Damage targets so SingleBurst heal is observable.
        for id in [ally_id, far_ally_id, enemy_id, infantry_id] {
            let unit = game_logic.find_object_mut(id).expect("unit");
            unit.health.current = unit.health.maximum * 0.25;
        }

        let ally_hp_before = game_logic.find_object(ally_id).unwrap().health.current;
        let far_hp_before = game_logic.find_object(far_ally_id).unwrap().health.current;
        let enemy_hp_before = game_logic.find_object(enemy_id).unwrap().health.current;
        let infantry_hp_before = game_logic.find_object(infantry_id).unwrap().health.current;
        let full_hp_before = game_logic.find_object(full_hp_id).unwrap().health.current;

        assert!(!game_logic.honesty_emergency_repair_ok());
        assert_eq!(game_logic.emergency_repairs().activation_count(), 0);

        let impact = Vec3::new(0.0, 0.0, 0.0);
        game_logic.queue_command(GameCommand {
            command_type: CommandType::DoSpecialPower {
                power_type: SpecialPowerType::EmergencyRepair,
                target: PowerTarget::Location(impact),
            },
            player_id: 0,
            command_id: 91,
            timestamp: std::time::SystemTime::now(),
            selected_units: vec![caster_id],
            modifier_keys: crate::command_system::ModifierKeys::default(),
        });
        game_logic.process_commands();

        assert!(
            game_logic.honesty_emergency_repair_activate_ok(),
            "Emergency Repair residual must record activation honesty"
        );
        assert!(
            game_logic.honesty_emergency_repair_heal_ok(),
            "Emergency Repair residual must record heal honesty"
        );
        assert!(
            game_logic.honesty_emergency_repair_ok(),
            "Emergency Repair host residual path honesty"
        );
        assert_eq!(game_logic.emergency_repairs().activation_count(), 1);
        assert!(
            (game_logic.emergency_repairs().activations()[0].radius - HOST_EMERGENCY_REPAIR_RADIUS)
                .abs()
                < 0.01,
            "retail residual radius 100"
        );
        assert_eq!(
            game_logic.emergency_repairs().activations()[0].level,
            HostEmergencyRepairLevel::One
        );

        let ally_hp_after = game_logic.find_object(ally_id).unwrap().health.current;
        let restored = ally_hp_after - ally_hp_before;
        assert!(
            (restored - HostEmergencyRepairLevel::One.heal_amount()).abs() < 0.05
                || restored > 0.0
                    && ally_hp_after
                        >= game_logic.find_object(ally_id).unwrap().health.maximum - 0.01,
            "in-radius damaged ally vehicle must receive Level1 heal (+100), restored={restored}"
        );
        assert!(
            (restored - 100.0).abs() < 0.05,
            "Level1 residual HealingAmount must be 100, got {restored}"
        );

        // Full-HP ally: no heal (not damaged residual).
        let full_hp_after = game_logic.find_object(full_hp_id).unwrap().health.current;
        assert!(
            (full_hp_after - full_hp_before).abs() < 0.01,
            "full-HP ally must not receive Emergency Repair residual"
        );

        // Out-of-radius ally: unaffected.
        let far_hp_after = game_logic.find_object(far_ally_id).unwrap().health.current;
        assert!(
            (far_hp_after - far_hp_before).abs() < 0.01,
            "out-of-radius ally must not receive Emergency Repair residual"
        );

        // Enemy residual: not healed (same-team filter).
        let enemy_hp_after = game_logic.find_object(enemy_id).unwrap().health.current;
        assert!(
            (enemy_hp_after - enemy_hp_before).abs() < 0.01,
            "enemy must not receive Emergency Repair residual"
        );

        // Infantry residual: KindOf VEHICLE only.
        let infantry_hp_after = game_logic.find_object(infantry_id).unwrap().health.current;
        assert!(
            (infantry_hp_after - infantry_hp_before).abs() < 0.01,
            "infantry must not receive Emergency Repair residual"
        );
    }

