        logic.objects.insert(aid, a);

        let mut vt = ThingTemplate::new("Vic");
        vt.add_kind_of(KindOf::Infantry);
        let vid = ObjectId(1102);
        let mut v = Object::new(vt, vid, Team::GLA);
        v.set_position(Vec3::new(80.0, 0.0, 0.0));
